                    getSetting<string>('kalina_voice_mode_tone_instruction', user),
                    getSetting<string>('kalina_voice_mode_custom_instruction', user),
                    getSetting<boolean>('kalina_voice_proactive_mode', user)
                ]);
                if (storedVoice) setVoiceModeVoice(storedVoice);
                if (storedPersona) setVoiceModePersonaInstruction(storedPersona);
                if (storedTone) setVoiceModeToneInstruction(storedTone);
                if (storedCustom) setVoiceModeCustomInstruction(storedCustom);
                if (storedProactive !== undefined) setIsVoiceProactiveMode(storedProactive);
            } catch (e) {
                console.error("Failed to load settings", e);
            }
        };
        loadSettings();
    }, [user]);

    useEffect(() => {
        getSetting<string>('kalina_api_key', user).then(storedApiKey => {
            if (storedApiKey) {
                try {
                    initializeAiClient(storedApiKey);
                    setApiKey(storedApiKey);
                } catch (e) {
                    console.error("Failed to initialize API key", e);
                }
            }
        });
    }, [user]);

    const onNewChat = useCallback(() => {
        handleNewChat();
        handleNavigate('chat');
        setImages([]);
        setFile(null);
        setAttachedNote(null);
        setInput('');
        setEditingMessageId(null);
        setSuggestions([]);
        setIsSelectionMode(false);
        setSelectedMessageIds(new Set());
    }, [handleNewChat]);

    const onSelectConversation = (id: string) => {
        handleSelectConversation(id);
        handleNavigate('chat');
    };

    const handleSetApiKey = (key: string) => {
        initializeAiClient(key);
        saveSetting('kalina_api_key', key, user);
        setApiKey(key);
        setIsApiKeyModalOpen(false);
    };

    const handleSendMessageWrapper = useCallback((prompt: string, images?: any[], file?: any, attachedNote?: Note | null, url?: string, isRetry = false) => {
        if (!apiKey) {
            setPendingApiKeyMessage({ prompt, images, file, attachedNote, url, isRetry });
            setIsApiKeyModalOpen(true);
            return;
        }
        setSuggestions([]);
        if (editingMessageId && activeConversation) {
            const messageIndex = activeConversation.messages.findIndex(m => m.id === editingMessageId);
            if (messageIndex !== -1) {
                conversationManager.updateConversationMessages(activeConversation.id, prev => prev.slice(0, messageIndex));
                handleSendMessage(prompt, images, file, attachedNote, url, undefined, false);
                setEditingMessageId(null);
                setImages([]);
                setFile(null);
                setAttachedNote(null);
                setInput('');
                return;
            }
        }
        handleSendMessage(prompt, images, file, attachedNote, url, undefined, isRetry);
        if (!isRetry) {
            setImages([]);
            setFile(null);
            setAttachedNote(null);
            setInput('');
        }
    }, [apiKey, editingMessageId, activeConversation, handleSendMessage, conversationManager]);

    const handleRetry = useCallback(() => {
        if (!activeConversation || activeConversation.messages.length === 0) return;
        let lastModelIndex = -1;
        for (let i = activeConversation.messages.length - 1; i >= 0; i--) {
            if (activeConversation.messages[i].role === 'model') {
                lastModelIndex = i;
                break;
            }
        }
        if (lastModelIndex !== -1) {
            const lastUserMessage = activeConversation.messages[lastModelIndex - 1];
            if (lastUserMessage?.role === 'user') {
                conversationManager.updateConversationMessages(activeConversation.id, prev => prev.slice(0, lastModelIndex));
                handleSendMessageWrapper(lastUserMessage.content, lastUserMessage.images, lastUserMessage.file, lastUserMessage.attachedNote, lastUserMessage.url, true);
            }
        }
    }, [activeConversation, conversationManager, handleSendMessageWrapper]);

    const handleEditMessage = (index: number, newContent: string) => {
        if (!activeConversation) return;
        const msg = activeConversation.messages[index];
        if (msg.role !== 'user') return;
        conversationManager.updateConversationMessages(activeConversation.id, prev => prev.slice(0, index));
        handleSendMessageWrapper(newContent, msg.images, msg.file, msg.attachedNote, msg.url);
    };

    const handleToolChange = (tool: Tool) => {
        setSelectedTool(tool);
        if (currentView === 'translator') handleNavigate('chat');
    };

    const handleViewUsageDetails = (conversationId: string) => {
        setViewingUsageConvoId(conversationId);
        handleNavigate('usage-detail');
    };

    const handleViewConvoDetails = (convoPair: any) => {
        setViewingConvo(convoPair);
        handleNavigate('convo-detail');
    };

    const handleStartEditImage = (image: any) => {
        setImageToEdit(image);
        handleNavigate('image-editor');
    };

    const handleSaveEditedImage = (newBase64: string) => {
        if (!imageToEdit) return;
        setImages(prev => {
            const newImages = [...prev];
            newImages[imageToEdit.index] = { base64: newBase64, mimeType: 'image/jpeg' };
            return newImages;
        });
        setImageToEdit(null);
        handleNavigate('chat');
    };

    const handleSaveEditor = (newText: string) => {
        setInput(newText);
        handleNavigate('chat');
    };

    const handleInteraction = useCallback((articleUrl: string, type: 'like' | 'bookmark') => {
        const key = type === 'like' ? 'liked' : 'bookmarked';
        const isCurrentlyActive = interactions[articleUrl]?.[key] ?? false;
        const newState = !isCurrentlyActive;

        if (type === 'bookmark') setBookmarkCount(prev => (prev !== null ? (newState ? prev + 1 : Math.max(0, prev - 1)) : null));

        // Update interaction state
        setInteractions(prev => ({...prev, [articleUrl]: { ...(prev[articleUrl] || { article_url: articleUrl, liked: false, bookmarked: false }), [key]: newState }}));

        // Update list of articles in Explore view
        setExploreArticles(prev => prev.map(art => art.url === articleUrl ? { ...art, [type === 'like' ? 'likes' : 'bookmarks']: (art[type === 'like' ? 'likes' : 'bookmarks'] || 0) + (newState ? 1 : -1) } : art));

        // Update current reading article if it matches
        if (articleForReading && articleForReading.url === articleUrl) {
            setArticleForReading(prev => prev ? ({
                ...prev,
                [type === 'like' ? 'likes' : 'bookmarks']: (prev[type === 'like' ? 'likes' : 'bookmarks'] || 0) + (newState ? 1 : -1)
            }) : null);
        }

        saveInteraction(user, { ...(interactions[articleUrl] || { article_url: articleUrl, liked: false, bookmarked: false }), [key]: newState });
        incrementStat(articleUrl, type === 'like' ? 'likes' : 'bookmarks', newState);
    }, [interactions, user, articleForReading]);

    const handleSaveVoiceConversation = useCallback(async (transcript: TranscriptMessage[]) => {
        if (transcript.length === 0) return;

        const newMessages: ChatMessage[] = transcript.map(t => ({
            id: t.id,
            role: t.role,
            content: t.text,
            timestamp: new Date().toISOString(),
            audioBase64: t.role === 'model' && t.audioChunks ? t.audioChunks[0] : undefined
        }));

        const newConversationId = crypto.randomUUID();
        const newConversation: Conversation = {
            id: newConversationId,
            title: "Voice Conversation", // Temporary title
            messages: newMessages,
            createdAt: new Date().toISOString(),
            summarizationFailed: false,
            isVoiceConversation: true
        };

        // Update state optimistically
        conversationManager.setConversations(prev => [newConversation, ...prev]);
        conversationManager.setActiveConversationId(newConversationId);

        // Save to DB
        await saveConversation(newConversation, user);

        // Generate Title
        const transcriptText = newMessages.map(m => `${m.role}: ${m.content}`).join('\n');
        generateTitleFromTranscript(transcriptText).then(title => {
            conversationManager.updateConversation(newConversationId, c => ({ ...c, title }));
        });

    }, [user, conversationManager]);

    const handleDeleteMessages = () => {
        if (!activeConversation) return;

        conversationManager.updateConversationMessages(activeConversation.id, (msgs) => {
            const idsToDelete = new Set(selectedMessageIds);

            // Also delete the AI response attached to a selected user message
            msgs.forEach((msg, index) => {
                if (msg.role === 'user' && selectedMessageIds.has(msg.id)) {
                    const nextMsg = msgs[index + 1];
                    if (nextMsg && nextMsg.role === 'model') {
                        idsToDelete.add(nextMsg.id);
                    }
                }
            });

            return msgs.filter(m => !idsToDelete.has(m.id));
        });

        setIsDeleteConfirmOpen(false);
        setIsSelectionMode(false);
        setSelectedMessageIds(new Set());
    };

    return (
        <>
            <NetworkTracker />
            {isSidebarOpen && <div onClick={() => setIsSidebarOpen(false)} className="fixed inset-0 bg-black/60 z-40 md:hidden" />}
            <div className="flex h-full bg-[#F9F6F2] dark:bg-[#191B1A] text-neutral-800 dark:text-white transition-colors duration-300">
                <Sidebar 
                    isMobileOpen={isSidebarOpen}
                    onMobileClose={() => setIsSidebarOpen(false)}
                    currentView={currentView}
                    onNavigate={handleNavigate}
                    onToggleSelectionMode={() => setIsSelectionMode(!isSelectionMode)}
                    isSelectionMode={isSelectionMode}
                    hasMessages={activeConversation?.messages.length > 0}
                />

                <div className="flex-1 flex flex-col overflow-hidden relative">
                    {!['live-conversation', 'editor', 'image-editor', 'code-preview'].includes(currentView) && (
                        <FloatingHeader
                            onOpenSidebar={() => setIsSidebarOpen(true)}
                            isChatView={true} 
                            conversations={sortedConversations}
                            activeConversationId={conversationManager.activeConversationId}
                            onSelectConversation={onSelectConversation}
                            onNewChat={onNewChat}
                            onDeleteMultipleConversations={setIdsToDelete}
                            onPinConversation={handlePinConversation}
                            onRenameConversation={handleRenameConversation}
                            onDeleteConversation={setSingleConvoToDelete}
                            conversationCount={conversationManager.conversations.length}
                            user={user}
                            userProfile={userProfile}
                            onOpenAuthModal={() => setIsAuthModalOpen(true)}
                            onOpenProfileModal={() => setIsProfileModalOpen(true)}
                            onLogout={logout}
                            onNavigate={handleNavigate}
                            randomExploreArticles={randomExplorePreviews}
                            currentView={currentView}
                            bookmarkCount={bookmarkCount}
                            onOpenBookmarks={() => setIsBookmarkFeedOpen(true)}
                            isProfileLoading={isProfileLoading}
                            notesSearchQuery={notesSearchQuery}
                            setNotesSearchQuery={setNotesSearchQuery}
                        />
                    )}

                    <div ref={scrollContainerRef} className={`flex-1 min-h-0 scrollbar-hide ${currentView === 'chat' ? `scroll-fade transition-[padding] duration-300 ease-in-out ${isChatInputExpanded ? 'pb-[7.2rem] md:pb-[9rem]' : 'pb-[4.5rem]'}` : ''} ${['live-conversation', 'reading', 'explore', 'article-reader', 'code-preview', 'settings', 'finance', 'notes', 'about', 'features'].includes(currentView) ? 'overflow-hidden' : 'overflow-y-auto'}`}>
                        <ViewRenderer
                            currentView={currentView}
                            showWelcomeScreen={showWelcomeScreen}
                            activeConversation={activeConversation}
                            conversations={conversationManager.conversations}
                            isLoading={chatHandler.isLoading}
                            isThinking={chatHandler.isThinking}
                            isSearchingWeb={chatHandler.isSearchingWeb}
                            ltm={ltm}
                            translatorUsage={translatorUsage}
                            handleRetry={handleRetry}
                            handleEditMessage={handleEditMessage}
                            handleSelectSuggestion={(s) => { if (s.prompt) setInput(s.prompt); }}
                            handleCancelStream={handleCancelStream}
                            setCurrentView={handleNavigate}
                            setLtm={setLtm}
                            scrollContainerRef={scrollContainerRef}
                            onCloseTranslator={() => handleNavigate('chat')}
                            onTranslationComplete={(t) => setTranslatorUsage(prev => ({ input: prev.input + t.input, output: prev.output + t.output }))}
                            setModalImage={setGalleryState}
                            setCodeForPreview={handleOpenCodePreview}
                            codeForPreview={codeForPreview}
                            viewingUsageConvoId={viewingUsageConvoId}
                            onViewUsageDetails={handleViewUsageDetails}
                            viewingConvo={viewingConvo}
                            onViewConvoDetails={handleViewConvoDetails}
                            onSaveEditor={handleSaveEditor}
                            editorInitialText={input}
                            onSaveEditedImage={handleSaveEditedImage}
                            imageToEdit={imageToEdit}
                            isSelectionMode={isSelectionMode}
                            selectedMessageIds={selectedMessageIds}
                            onToggleMessageSelection={id => setSelectedMessageIds(prev => { const n = new Set(prev); if (n.has(id)) n.delete(id); else n.add(id); return n; })}
                            moleculeForFullScreen={moleculeForFullScreen}
                            onMaximizeMoleculeViewer={setMoleculeForFullScreen}
                            onViewSources={setSourcesForViewer}
                            onGoToMemorySource={id => { setScrollToMessageId(id); handleNavigate('chat'); }}
                            voiceModeVoice={voiceModeVoice}
                            setVoiceModeVoice={setVoiceModeVoice}
                            voiceModePersonaInstruction={voiceModePersonaInstruction}
                            setVoiceModePersonaInstruction={setVoiceModePersonaInstruction}
                            voiceModeToneInstruction={voiceModeToneInstruction}
                            setVoiceModeToneInstruction={setVoiceModeToneInstruction}
                            voiceModeCustomInstruction={voiceModeCustomInstruction}
                            setCustomInstruction={setVoiceModeCustomInstruction}
                            isVoiceProactiveMode={isVoiceProactiveMode}
                            setIsVoiceProactiveMode={setIsVoiceProactiveMode}
                            onSaveVoiceConversation={handleSaveVoiceConversation}
                            onBackFromLive={() => handleNavigate('chat')}
                            voiceContinuationContext={voiceContinuationContext}
                            onPlayAudioRequest={audioPlayer.togglePlayPause}
                            playerState={audioPlayer.playerState}
                            onAudioSeek={audioPlayer.seek}
                            user={user}
                            userProfile={userProfile}
                            onReadArticle={a => { setArticleForReading(a); handleNavigate('article-reader'); }}
                            articleForReading={articleForReading}
                            exploreCurrentIndex={exploreCurrentIndex}
                            setExploreCurrentIndex={setExploreCurrentIndex}
                            exploreActiveCategory={exploreActiveCategory}
                            setExploreActiveCategory={setExploreActiveCategory}
                            exploreArticles={exploreArticles}
                            setExploreArticles={setExploreArticles}
                            exploreIsLoading={exploreIsLoading}
                            exploreError={exploreError}
                            interactions={interactions}
                            handleInteraction={handleInteraction}
                            isBookmarkFeedOpen={isBookmarkFeedOpen}
                            setIsBookmarkFeedOpen={setIsBookmarkFeedOpen}
                            bookmarkCount={bookmarkCount}
                            onDeleteMemory={deleteMemory}
                            onDeleteMemories={deleteMemories}
                            onDeleteConversation={handleDeleteConversation}
                            setInput={setInput}
                            setEditingMessageId={setEditingMessageId}
                            suggestions={suggestions}
                            onSendSuggestion={s => handleSendMessageWrapper(s)}
                            uiPreferences={uiPreferences}
                            onUpdatePreferences={handleUpdatePreferences}
                            currentTheme={isDarkMode ? 'dark' : 'light'}
                            onThemeChange={handleThemeChange}
                            isConversationsLoading={isConversationsLoading}
                            notesSearchQuery={notesSearchQuery}
                        />
                    </div>

                    {currentView === 'chat' && (
                        <div className={`absolute bottom-0 left-0 w-full z-20 pointer-events-none flex justify-center transition-[padding] duration-300 ease-in-out ${isChatInputExpanded ? 'px-0 pb-0 md:px-4 md:pb-6' : 'px-4 pb-6'}`}>
                            <div className={`w-full max-w-3xl pointer-events-auto transition-all duration-300 ${isChatInputExpanded ? 'max-w-full md:max-w-3xl md:mb-6' : ''}`}>
                                {isSelectionMode ? (
                                    <SelectionToolbar selectedCount={selectedMessageIds.size} onDelete={() => setIsDeleteConfirmOpen(true)} onCancel={() => setIsSelectionMode(false)} />
                                ) : (
                                    <ChatInput 
                                        onSendMessage={handleSendMessageWrapper}
                                        isLoading={chatHandler.isLoading}
                                        elapsedTime={elapsedTime}
                                        selectedTool={selectedTool}
                                        onToolChange={handleToolChange}
                                        activeSuggestion={activeSuggestion}
                                        onClearSuggestion={() => setActiveSuggestion(null)}
                                        onCancelStream={() => setIsStopConfirmOpen(true)}
                                        models={allModels} // Pass merged models
                                        selectedChatModel={selectedChatModel}
                                        onSelectChatModel={setSelectedChatModel}
                                        apiKey={apiKey}
                                        onOpenApiKeyModal={() => setIsApiKeyModalOpen(true)}
                                        showConversationJumper={!isScrolledToBottom && !chatHandler.isLoading}
                                        onNavigate={handleNavigateJumper}
                                        isAtStartOfConversation={isAtStart}
                                        isAtEndOfConversation={isAtEnd}
                                        images={images}
                                        setImages={setImages}
                                        file={file}
                                        setFile={setFile}
                                        setModalImage={setGalleryState}
                                        onEditImage={handleStartEditImage}
                                        input={input}
                                        setInput={setInput}
                                        onOpenFullScreenEditor={() => handleNavigate('editor')}
                                        onStartVoiceConversation={() => handleNavigate('live-conversation')}
                                        isVoiceConversation={activeConversation?.isVoiceConversation}
                                        onContinueVoiceConversation={() => handleNavigate('live-conversation')}
                                        editingMessageId={editingMessageId}
                                        onCancelEdit={() => { setEditingMessageId(null); setInput(''); }}
                                        onExpandedChange={setIsChatInputExpanded}
                                        attachedNote={attachedNote}
                                        onAttachNote={() => setIsNotePickerOpen(true)}
                                        onRemoveNote={() => setAttachedNote(null)}
                                        // Pass new custom model handlers
                                        onAddModel={handleAddCustomModel}
                                        onDeleteModel={handleDeleteCustomModel}
                                    />
                                )}
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Confirmation Modals */}
            <ConfirmationModal isOpen={isDeleteConfirmOpen} onClose={() => setIsDeleteConfirmOpen(false)} onConfirm={handleDeleteMessages} title="Delete Messages" message="Confirm deleting selected messages." confirmButtonText="Delete" confirmButtonVariant="danger" />
            <ConfirmationModal isOpen={isBulkDeleteConfirmOpen} onClose={() => setIsBulkDeleteConfirmOpen(false)} onConfirm={() => { conversationManager.handleDeleteMultipleConversations(idsToDelete); setIsBulkDeleteConfirmOpen(false); }} title="Delete Conversations" message="Delete all selected conversations?" confirmButtonText="Delete All" confirmButtonVariant="danger" />
            <ConfirmationModal isOpen={!!singleConvoToDelete} onClose={() => setSingleConvoToDelete(null)} onConfirm={() => { if(singleConvoToDelete) handleDeleteConversation(singleConvoToDelete); setSingleConvoToDelete(null); }} title="Delete Conversation" message="Permanently delete this chat?" confirmButtonText="Delete" confirmButtonVariant="danger" />
            <ConfirmationModal isOpen={isStopConfirmOpen} onClose={() => setIsStopConfirmOpen(false)} onConfirm={() => { handleCancelStream(); setIsStopConfirmOpen(false); }} title="Stop Generating" message="Stop current response?" confirmButtonText="Stop" confirmButtonVariant="danger" />

            <ApiKeyModal isOpen={isApiKeyModalOpen} onSetApiKey={handleSetApiKey} onClose={() => setIsApiKeyModalOpen(false)} currentApiKey={apiKey} />
            <AuthModal isOpen={isAuthModalOpen} onClose={() => setIsAuthModalOpen(false)} />
            {user && <ProfileModal isOpen={isProfileModalOpen} onClose={() => setIsProfileModalOpen(false)} user={user} userProfile={userProfile} onProfileUpdate={p => setUserProfile(prev => ({...prev, ...p}))} />}
            {galleryState && <ImageModal images={galleryState.images} initialIndex={galleryState.index} onClose={() => setGalleryState(null)} />}
            {sourcesForViewer && <SourceViewer sources={sourcesForViewer} onClose={() => setSourcesForViewer(null)} />}
            <NotePickerModal isOpen={isNotePickerOpen} onClose={() => setIsNotePickerOpen(false)} onSelectNote={setAttachedNote} user={user} />
        </>
    );
};

export default App;

