// Add type definitions for the Web Speech API
interface SpeechRecognition {
    continuous: boolean;
    interimResults: boolean;
    lang: string;
    onstart: () => void;
    onend: () => void;
    onerror: (event: { error: string }) => void;
    onresult: (event: SpeechRecognitionEvent) => void;
    start: () => void;
    stop: () => void;
}

interface SpeechRecognitionEvent extends Event {
    readonly resultIndex: number;
    readonly results: SpeechRecognitionResultList;
}

interface SpeechRecognitionResultList {
    readonly length: number;
    [index: number]: SpeechRecognitionResult;
}

interface SpeechRecognitionResult {
    readonly length: number;
    [index: number]: SpeechRecognitionAlternative;
}

interface SpeechRecognitionAlternative {
    readonly transcript: string;
}

interface ChatInputProps {
  onSendMessage: (message: string, images?: { base64: string; mimeType: string; }[], file?: { base64: string; mimeType: string; name: string; size: number; } | null, attachedNote?: Note | null, url?: string) => void;
  isLoading: boolean;
  elapsedTime: number;
  selectedTool: Tool;
  onToolChange: (tool: Tool) => void;
  activeSuggestion: Suggestion | null;
  onClearSuggestion: () => void;
  onCancelStream: () => void;
  models: ModelInfo[];
  selectedChatModel: ChatModel;
  onSelectChatModel: (model: ChatModel) => void;
  apiKey: string | null;
  onOpenApiKeyModal: () => void;
  showConversationJumper: boolean;
  onNavigate: (direction: 'up' | 'down') => void;
  isAtStartOfConversation: boolean;
  isAtEndOfConversation: boolean;
  images: { base64: string; mimeType: string; }[];
  setImages: React.Dispatch<React.SetStateAction<{ base64: string; mimeType: string; }[]>>;
  file: { base64: string; mimeType: string; name: string; size: number; } | null;
  setFile: React.Dispatch<React.SetStateAction<{ base64: string; mimeType: string; name: string; size: number; } | null>>;
  setModalImage: (data: { images: string[]; index: number } | null) => void;
  onEditImage: (image: { index: number; base64: string; mimeType: string; }) => void;
  input: string;
  setInput: React.Dispatch<React.SetStateAction<string>>;
  onOpenFullScreenEditor: () => void;
  onStartVoiceConversation: () => void;
  isVoiceConversation?: boolean;
  onContinueVoiceConversation: () => void;
  editingMessageId?: string | null;
  onCancelEdit?: () => void;
  onExpandedChange?: (isExpanded: boolean) => void;
  // Note props
  attachedNote?: Note | null;
  onAttachNote?: () => void;
  onRemoveNote?: () => void;
  // Custom Model Props
  onAddModel?: (id: string, name: string) => void;
  onDeleteModel?: (id: string) => void;
}

