        <path d="M12 2C6.477 2 2 6.477 2 12C2 17.523 6.477 22 12 22" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
        <path d="M12 2C17.523 2 22 6.477 22 12C22 17.523 17.523 22 12 22" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
        <path d="M12 2C14.209 2 16 3.791 16 6C16 8.209 14.209 10 12 10C9.791 10 8 8.209 8 6C8 3.791 9.791 2 12 2Z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
        <path d="M12 10V14" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
        <path d="M8 16H16" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
        <circle cx="8" cy="16" r="1.5" stroke="currentColor" strokeWidth="2"/>
        <circle cx="16" cy="16" r="1.5" stroke="currentColor" strokeWidth="2"/>
    </svg>
);


export const tools: { id: Tool; name: string; description: string; icon: React.ElementType }[] = [
    { id: 'smart', name: 'Smart Mode', description: 'Automatically uses the best tool for the job.', icon: SmartModeIcon },
    { id: 'webSearch', name: 'Web Search', description: 'Searches the web for real-time info.', icon: Globe },
    { id: 'urlReader', name: 'URL Reader', description: 'Reads content from a web page URL.', icon: UrlReaderIcon },
    { id: 'chemistry', name: 'Chemistry', description: 'Visualize molecules and solve chemistry problems.', icon: ChemistryIcon },
    { id: 'thinking', name: 'Thinking', description: 'Shows the AI\'s step-by-step thought process.', icon: ThinkingIcon },
];

const formatFileSize = (bytes: number): string => {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
};

const ChatInput: React.FC<ChatInputProps> = ({ 
    onSendMessage, 
    isLoading,
    elapsedTime,
    selectedTool,
    onToolChange,
    activeSuggestion,
    onClearSuggestion,
    onCancelStream,
    models,
    selectedChatModel,
    onSelectChatModel,
    apiKey,
    onOpenApiKeyModal,
    showConversationJumper,
    onNavigate,
    isAtStartOfConversation,
    isAtEndOfConversation,
    images,
    setImages,
    file,
    setFile,
    setModalImage,
    onEditImage,
    input,
    setInput,
    onOpenFullScreenEditor,
    onStartVoiceConversation,
    isVoiceConversation,
    onContinueVoiceConversation,
    editingMessageId,
    onCancelEdit,
    onExpandedChange,
    attachedNote,
    onAttachNote,
    onRemoveNote,
    onAddModel,
    onDeleteModel
}) => {
  const [urlInput, setUrlInput] = useState('');
  const [isAttachmentMenuOpen, setIsAttachmentMenuOpen] = useState(false);
  const [isProcessingAttachment, setIsProcessingAttachment] = useState(false);
  const [isMaxHeight, setIsMaxHeight] = useState(false);
  const [isFocused, setIsFocused] = useState(false);

  const [isListening, setIsListening] = useState(false);
  const [isSpeechSupported, setIsSpeechSupported] = useState(false);
  const recognitionRef = useRef<SpeechRecognition | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const imageInputRef = useRef<HTMLInputElement>(null);
  const cameraInputRef = useRef<HTMLInputElement>(null);
  const attachmentMenuRef = useRef<HTMLDivElement>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const inputContainerRef = useRef<HTMLDivElement>(null);

  // Logic for Expanded State:
  const isExpanded = isFocused || images.length > 0 || !!file || !!attachedNote || selectedTool === 'urlReader' || !!editingMessageId;

  useEffect(() => {
      onExpandedChange?.(isExpanded);
  }, [isExpanded, onExpandedChange]);

  const formatTime = (ms: number) => {
    if (!ms || ms < 0) return '0.0s';
    return `${(ms / 1000).toFixed(1)}s`;
  };

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
        setIsSpeechSupported(true);
        const recognition: SpeechRecognition = new SpeechRecognition();
        recognition.continuous = false;
        recognition.interimResults = false;
        recognition.lang = 'en-US';

        recognition.onresult = (event: SpeechRecognitionEvent) => {
            const transcript = event.results[event.results.length - 1][0].transcript.trim();
            setInput(prev => (prev ? prev.trim() + ' ' : '') + transcript);
        };

        recognition.onstart = () => setIsListening(true);
        recognition.onend = () => setIsListening(false);
        recognition.onerror = (event) => {
            console.error('Speech recognition error:', event.error);
            setIsListening(false);
        };
        recognitionRef.current = recognition;
    }
  }, [setInput]);

  const handleToggleListening = () => {
    if (!recognitionRef.current) return;
    if (isListening) {
        recognitionRef.current.stop();
    } else {
        recognitionRef.current.start();
    }
  };

  const placeholderText = () => {
      if (isLoading) return "Processing...";
      if (isListening) return "Listening...";
      if (editingMessageId) return "Editing message...";
      if (selectedTool === 'urlReader') return "Ask a question about the URL above...";
      if (images.length > 0) return `Ask a question about the ${images.length} image(s)...`;
      if (file) return `Ask a question about ${file.name}...`;
      if (attachedNote) return `Discuss "${attachedNote.title || 'Untitled Note'}"...`;
      if (isVoiceConversation) return "Ask a follow-up question, or continue the voice session...";
      return "Ask anything...";
  }

  const placeholder = placeholderText();

  useLayoutEffect(() => {
    if (textareaRef.current) {
        if (isExpanded) {
            textareaRef.current.style.height = 'auto';
            const scrollHeight = textareaRef.current.scrollHeight;
            const minHeight = 80;
            textareaRef.current.style.height = `${Math.max(scrollHeight, minHeight)}px`;

            // Check if scrollHeight has reached roughly 50% of screen height
            const maxHeight = window.innerHeight * 0.5;
            setIsMaxHeight(scrollHeight >= maxHeight);
        } else {
            textareaRef.current.style.height = '4rem';
            setIsMaxHeight(false);
        }
    }
  }, [input, placeholder, isExpanded]);

  useEffect(() => {
    if (activeSuggestion) {
        setInput(activeSuggestion.prompt);
        setIsFocused(true);
    }
  }, [activeSuggestion, setInput]);

  useEffect(() => {
    if (editingMessageId && textareaRef.current) {
        textareaRef.current.focus();
        setIsFocused(true);
    }
  }, [editingMessageId]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (inputContainerRef.current && !inputContainerRef.current.contains(event.target as Node)) {
            // Clicked outside input container
        }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [editingMessageId, onCancelEdit]);

    const handleFileChange = (event: ChangeEvent<HTMLInputElement>) => {
        const selectedFiles = event.target.files;
        if (!selectedFiles || selectedFiles.length === 0) return;

        const imageFiles = Array.from(selectedFiles).filter((f: File) => f.type.startsWith('image/'));
        const otherFiles = Array.from(selectedFiles).filter((f: File) => !f.type.startsWith('image/'));

        if (imageFiles.length > 0) {
            setIsProcessingAttachment(true);
            const filesToAdd = imageFiles.slice(0, 10 - images.length);
            if (filesToAdd.length === 0) {
                setIsProcessingAttachment(false);
                return;
            }

            const imagePromises = filesToAdd.map((file: File) => 
                new Promise<{ base64: string, mimeType: string }>((resolve, reject) => {
                    const reader = new FileReader();
                    reader.onloadend = async () => {
                        const base64String = (reader.result as string).split(',')[1];
                        // Removed compression to send original quality to AI
                        resolve({ base64: base64String, mimeType: file.type });
                    };
                    reader.onerror = reject;
                    reader.readAsDataURL(file);
                })
            );

            Promise.all(imagePromises)
                .then(newImages => setImages(prev => [...prev, ...newImages]))
                .catch(console.error)
                .finally(() => setIsProcessingAttachment(false));

            setFile(null);
            if (onRemoveNote) onRemoveNote();
        } 
        else if (otherFiles.length > 0) {
            const selectedFile = otherFiles[0] as File;
            setIsProcessingAttachment(true);
            const reader = new FileReader();
            reader.onloadend = () => {
                const base64String = (reader.result as string).split(',')[1];
                setFile({
                    base64: base64String,
                    mimeType: selectedFile.type,
                    name: selectedFile.name,
                    size: selectedFile.size,
                });
                setImages([]);
                if (onRemoveNote) onRemoveNote();
                setIsProcessingAttachment(false);
            };
            reader.readAsDataURL(selectedFile as Blob);
        }

        if (event.target) {
            event.target.value = '';
        }
    };

  const handleSend = () => {
    const messageToSend = input.trim();
    const urlToSend = selectedTool === 'urlReader' ? urlInput.trim() : undefined;

    if ((messageToSend || images.length > 0 || file || attachedNote || urlToSend) && !isLoading) {
      onSendMessage(messageToSend, images.length > 0 ? images : undefined, file ?? undefined, attachedNote ?? undefined, urlToSend);
      setUrlInput('');
    }
  };

  const handleKeyPress = (event: KeyboardEvent<HTMLTextAreaElement>) => {
    const isMobile = window.matchMedia("(max-width: 768px)").matches;
    if (event.key === 'Enter' && !event.shiftKey && !isMobile) {
        event.preventDefault();
        handleSend();
    }
  };

  const handlePaste = (event: React.ClipboardEvent<HTMLTextAreaElement>) => {
    if (images.length >= 10) return;
    const pastedFile = Array.from(event.clipboardData.files).find((f: File) => f.type.startsWith('image/'));
    if (pastedFile) {
      event.preventDefault();
      setIsProcessingAttachment(true);
      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64String = (reader.result as string).split(',')[1];
        // Directly set base64 without compression
        setImages(prev => [...prev, { base64: base64String, mimeType: (pastedFile as File).type }]);
        setIsProcessingAttachment(false);
      };
      reader.readAsDataURL(pastedFile as Blob);
    }
  }

  const handlePasteUrl = async () => {
    try {
        const text = await navigator.clipboard.readText();
        setUrlInput(text);
    } catch (error) {
        console.error('Failed to read clipboard contents: ', error);
    }
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (attachmentMenuRef.current && !attachmentMenuRef.current.contains(event.target as Node)) setIsAttachmentMenuOpen(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleClearSuggestionWithInput = () => {
    onClearSuggestion();
    setInput('');
  }

  const handleTriggerInput = (ref: React.RefObject<HTMLInputElement>) => {
    ref.current?.click();
    setIsAttachmentMenuOpen(false);
  };

  const handleAttachNoteClick = () => {
      if (onAttachNote) onAttachNote();
      setIsAttachmentMenuOpen(false);
  }

  const handleContainerClick = (e: React.MouseEvent<HTMLDivElement>) => {
    const target = e.target as HTMLElement;
    if (target.closest('button') || target.closest('input') || (attachmentMenuRef.current && attachmentMenuRef.current.contains(target))) return;
    textareaRef.current?.focus();
    setIsFocused(true);
  };

  const handleRemoveImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
  };

  const handleRemoveFile = () => {
    setFile(null);
  };

  const hasContent = !!input.trim() || images.length > 0 || file || attachedNote || (selectedTool === 'urlReader' && !!urlInput.trim());
  const isSendDisabled = isProcessingAttachment || !hasContent;

  const MicButton = () => (
    <button
        onClick={handleToggleListening}
        disabled={isLoading || !isSpeechSupported}
        className={`flex items-center justify-center w-9 h-9 p-2 rounded-full transition-all duration-200 ${
            isListening 
                ? 'bg-red-500 text-white animate-pulse' 
                : 'text-neutral-500 dark:text-gray-400 hover:bg-neutral-100 dark:hover:bg-gray-700/70'
            } disabled:opacity-50 disabled:cursor-not-allowed`}
        aria-label={isListening ? "Stop listening" : "Start voice input"}
    >
        <Mic className="h-5 w-5" />
    </button>
  );

  const getFileIcon = (mimeType: string) => {
      if (mimeType.includes('pdf')) return <FileText className="w-6 h-6 text-red-500" />;
      if (mimeType.includes('sheet') || mimeType.includes('excel')) return <FileSpreadsheet className="w-6 h-6 text-green-500" />;
      if (mimeType.includes('presentation') || mimeType.includes('powerpoint')) return <Presentation className="w-6 h-6 text-orange-500" />;
      return <FileIcon className="w-6 h-6 text-blue-500" />;
  };

  const openImageModal = (index: number) => {
      const imagesList = images.map(img => `data:${img.mimeType};base64,${img.base64}`);
      setModalImage({ images: imagesList, index });
  };

  return (
    <>
      <div className="flex flex-col gap-1 relative">
           {/* Hidden file inputs */}
          <input ref={cameraInputRef} type="file" capture="user" accept="image/*" onChange={handleFileChange} className="hidden" />
          <input ref={imageInputRef} type="file" accept="image/png, image/jpeg, image/webp" onChange={handleFileChange} className="hidden" multiple />
          <input ref={fileInputRef} type="file" accept="application/pdf, text/plain" onChange={handleFileChange} className="hidden" />

          {/* Floating Conversation Jumpers - Refined Unified Pill Style */}
          {showConversationJumper && (
            <div className="absolute right-0 -top-12 flex items-center gap-1 p-1 bg-white/80 dark:bg-[#1e1f22]/90 backdrop-blur-xl border border-neutral-200/60 dark:border-white/10 rounded-full z-20 pointer-events-auto mr-1 shadow-none">
                <button 
                    onClick={(e) => { e.preventDefault(); if ('vibrate' in navigator) navigator.vibrate(20); onNavigate('up'); }} 
                    disabled={isLoading || isAtStartOfConversation} 
                    className="flex items-center justify-center w-8 h-8 text-neutral-500 hover:text-neutral-900 dark:text-neutral-400 dark:hover:text-white rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors disabled:opacity-30 disabled:cursor-not-allowed" 
                    aria-label="Jump to previous message"
                >
                    <ChevronUp className="h-5 w-5" />
                </button>
                <div className="w-px h-4 bg-neutral-200 dark:bg-white/10" />
                <button 
                    onClick={(e) => { e.preventDefault(); if ('vibrate' in navigator) navigator.vibrate(20); onNavigate('down'); }} 
                    disabled={isLoading || isAtEndOfConversation} 
                    className="flex items-center justify-center w-8 h-8 text-neutral-500 hover:text-neutral-900 dark:text-neutral-400 dark:hover:text-white rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors disabled:opacity-30 disabled:cursor-not-allowed" 
                    aria-label="Jump to next message"
                >
                    <ChevronDown className="h-5 w-5" />
                </button>
            </div>
          )}

          {/* Suggestion Pill */}
          {activeSuggestion && (
            <div className="mx-4 p-2 pl-3 bg-amber-50 dark:bg-amber-900/40 border border-amber-200 dark:border-amber-800 rounded-xl flex self-start items-center gap-2 text-sm mb-1 animate-fade-in-up">
              {activeSuggestion.icon}
              <span className="text-amber-800 dark:text-amber-200 line-clamp-1 font-medium">{activeSuggestion.text}</span>
              <button onClick={handleClearSuggestionWithInput} className="p-1.5 rounded-full text-amber-500 dark:text-amber-300 hover:bg-amber-100 dark:hover:bg-amber-800/60 transition-colors flex-shrink-0" aria-label="Clear suggestion">
                  <X className="h-4 w-4" />
              </button>
            </div>
          )}

          {/* Attachments Preview Area (Above Input) */}
          {(images.length > 0 || file || attachedNote) && (
              <div className="flex gap-3 overflow-x-auto scrollbar-hide items-end mb-1 px-4 pt-3 pointer-events-auto animate-fade-in-up">
                  {/* Images */}
                  {images.map((img, idx) => (
                      <div key={idx} className="relative group flex-shrink-0 pt-3">
                          <div className="relative rounded-xl overflow-hidden border border-white/20 dark:border-white/10 w-24 h-24 shadow-lg cursor-pointer" onClick={() => openImageModal(idx)}>
                              <img src={`data:${img.mimeType};base64,${img.base64}`} alt="preview" className="w-full h-full object-cover" />

                              {/* Edit Overlay */}
                              <div className="absolute inset-0 bg-black/0 group-hover:bg-black/20 transition-colors" />
                          </div>

                          {/* Action Buttons */}
                          <button 
                              onClick={(e) => { e.stopPropagation(); onEditImage({ index: idx, base64: img.base64, mimeType: img.mimeType }); }}
                              className="absolute top-4 left-1 p-1.5 bg-black/60 text-white rounded-full hover:bg-black/80 transition-colors opacity-0 group-hover:opacity-100"
                              title="Edit Image"
                          >
                              <Pencil className="w-3.5 h-3.5" />
                          </button>

                          <button 
                              onClick={(e) => { e.stopPropagation(); handleRemoveImage(idx); }}
                              className="absolute top-1 -right-2 p-1 bg-white dark:bg-gray-700 rounded-full text-gray-500 hover:text-red-500 shadow-md border border-gray-200 dark:border-gray-600 transition-colors z-10"
                              title="Remove"
                          >
                              <X className="w-3.5 h-3.5" />
                          </button>
                      </div>
                  ))}

                  {/* File */}
                  {file && (
                      <div className="relative group flex-shrink-0 pt-3">
                          <div className="flex items-center gap-3 p-3 bg-white dark:bg-[#2E2F33] rounded-xl border border-neutral-200 dark:border-gray-700 shadow-lg h-16 max-w-[200px]">
                              <div className="p-2 bg-neutral-100 dark:bg-white/5 rounded-lg flex-shrink-0">
                                  {getFileIcon(file.mimeType)}
                              </div>
                              <div className="flex flex-col min-w-0">
                                  <span className="text-sm font-semibold truncate text-neutral-800 dark:text-gray-100">{file.name}</span>
                                  <span className="text-[10px] text-neutral-500 dark:text-gray-400 font-medium uppercase">{formatFileSize(file.size)}</span>
                              </div>
                          </div>
                          <button 
                              onClick={(e) => { e.stopPropagation(); handleRemoveFile(); }}
                              className="absolute top-1 -right-2 p-1 bg-white dark:bg-gray-700 rounded-full text-gray-500 hover:text-red-500 shadow-md border border-gray-200 dark:border-gray-600 transition-colors z-10"
                          >
                              <X className="w-3.5 h-3.5" />
                          </button>
                      </div>
                  )}

                  {/* Attached Note Preview */}
                  {attachedNote && (
                      <div className="relative group flex-shrink-0 pt-3">
                          <div className="flex items-center gap-3 p-3 bg-white dark:bg-[#2E2F33] rounded-xl border border-neutral-200 dark:border-gray-700 shadow-lg h-16 max-w-[200px]">
                              <div className="p-2 bg-amber-100 dark:bg-amber-900/30 rounded-lg flex-shrink-0">
                                  <StickyNote className="w-6 h-6 text-amber-600 dark:text-amber-400" />
                              </div>
                              <div className="flex flex-col min-w-0">
                                  <span className="text-sm font-semibold truncate text-neutral-800 dark:text-gray-100">{attachedNote.title || 'Untitled'}</span>
                                  <span className="text-[10px] text-neutral-500 dark:text-gray-400 font-medium uppercase">Note</span>
                              </div>
                          </div>
                          <button 
                              onClick={(e) => { e.stopPropagation(); if(onRemoveNote) onRemoveNote(); }}
                              className="absolute top-1 -right-2 p-1 bg-white dark:bg-gray-700 rounded-full text-gray-500 hover:text-red-500 shadow-md border border-gray-200 dark:border-gray-600 transition-colors z-10"
                          >
                              <X className="w-3.5 h-3.5" />
                          </button>
                      </div>
                  )}
              </div>
          )}

          {/* Main Chat Input Container */}
          <div 
            ref={inputContainerRef}
            onClick={handleContainerClick} 
            className={`relative flex flex-col justify-center cursor-text transition-all duration-300 ease-[cubic-bezier(0.34,1.56,0.64,1)] outline-none bg-white dark:bg-[#1e1f22] backdrop-blur-xl border 
                ${editingMessageId 
                    ? 'border-amber-400 dark:border-amber-500/80 shadow-[0_0_15px_-3px_rgba(251,191,36,0.15)]' 
                    : 'border-neutral-200/60 dark:border-gray-800'
                }
                ${isExpanded 
                    ? 'min-h-[8rem] rounded-t-[2rem] rounded-b-none md:rounded-b-[2rem] border-b-0 md:border-b border-x-0 md:border-x md:border-neutral-200/60 md:mb-0' 
                    : 'min-h-[4rem] rounded-[2rem]'
                }
            `}
            style={{ WebkitTapHighlightColor: 'transparent', outline: 'none', boxShadow: 'none' }}
          >
            {/* Editing Badge - Attached to top border */}
            {editingMessageId && onCancelEdit && (
                <div className="absolute -top-3 left-6 z-30 flex items-center gap-2 pl-3 pr-2 py-0.5 bg-amber-50 dark:bg-[#1e1f22] border border-amber-300 dark:border-amber-600 rounded-full shadow-sm text-xs font-bold text-amber-700 dark:text-amber-400 uppercase tracking-wide">
                    <span className="flex items-center gap-1">
                        <Pencil className="w-3 h-3" />
                        Editing
                    </span>
                    <div className="w-px h-3 bg-amber-300 dark:bg-amber-700 mx-0.5" />
                    <button 
                        onClick={(e) => { e.stopPropagation(); onCancelEdit(); }} 
                        className="hover:bg-amber-100 dark:hover:bg-amber-900/50 rounded-full p-0.5 transition-colors"
                        aria-label="Cancel edit"
                    >
                        <X className="w-3 h-3" />
                    </button>
                </div>
            )}

            {/* Textarea Section */}
            <div className="w-full relative z-10">
                {/* Top Right Maximizer - Only visible when content is very long */}
                {isMaxHeight && (
                  <Tooltip content="Full Screen Editor">
                      <button
                          onClick={(e) => { e.stopPropagation(); onOpenFullScreenEditor(); }}
                          className="absolute top-2 right-4 p-1.5 rounded-full bg-black/5 dark:bg-white/10 backdrop-blur-sm text-neutral-500 dark:text-gray-400 hover:bg-black/10 dark:hover:bg-white/20 transition-all z-20"
                          aria-label="Open full screen editor"
                      >
                          <Maximize2 className="h-3 w-3" />
                      </button>
                  </Tooltip>
                )}

                {selectedTool === 'urlReader' && (
                    <div className="mx-4 mt-2 mb-1 relative z-30 bg-transparent backdrop-blur-md border border-black/10 dark:border-white/10 rounded-xl px-3 py-2 flex items-center gap-2 animate-fade-in-up">
                        <UrlReaderIcon className="h-4 w-4 text-black/70 dark:text-gray-400 flex-shrink-0" />
                        <input 
                            type="text" 
                            value={urlInput} 
                            onChange={(e) => setUrlInput(e.target.value)} 
                            placeholder="Enter a URL to read..." 
                            className="w-full bg-transparent focus:outline-none text-black dark:text-gray-200 placeholder:text-black/60 dark:placeholder:text-gray-500 text-sm" 
                            disabled={isLoading} 
                        />
                        <button 
                            onClick={handlePasteUrl} 
                            className="p-1.5 text-black/70 dark:text-gray-400 hover:bg-white/20 dark:hover:bg-white/10 rounded-full transition-colors" 
                            aria-label="Paste URL" 
                            disabled={isLoading}
                        >
                            <ClipboardPaste className="h-4 w-4" />
                        </button>
                    </div>
                )}

                 <textarea 
                    ref={textareaRef} 
                    rows={1} 
                    value={input} 
                    onChange={(e) => setInput(e.target.value)} 
                    onFocus={() => setIsFocused(true)}
                    onBlur={() => {
                        setTimeout(() => {
                            if (!images.length && !file && !attachedNote && !editingMessageId && !inputContainerRef.current?.contains(document.activeElement)) {
                                setIsFocused(false);
                            }
                        }, 150);
                    }}
                    onKeyPress={handleKeyPress} 
                    onPaste={handlePaste} 
                    placeholder={placeholder} 
                    disabled={isLoading} 
