interface ModelSelectorProps {
    models: ModelInfo[];
    selectedChatModel: ChatModel;
    onSelectChatModel: (model: ChatModel) => void;
    apiKey: string | null;
    onOpenApiKeyModal: () => void;
    onAddModel?: (id: string, name: string) => void;
    onDeleteModel?: (id: string) => void;
}

const ModelSelector: React.FC<ModelSelectorProps> = ({
    models,
    selectedChatModel,
    onSelectChatModel,
    apiKey,
    onOpenApiKeyModal,
    onAddModel,
    onDeleteModel
}) => {
    const [isOpen, setIsOpen] = useState(false);
    const [isAddingModel, setIsAddingModel] = useState(false);
    const [newModelId, setNewModelId] = useState('');
    const [newModelName, setNewModelName] = useState('');
    const selectorRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (selectorRef.current && !selectorRef.current.contains(event.target as Node)) {
                setIsOpen(false);
                setIsAddingModel(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, []);

    const maskApiKey = (key: string | null): string => {
        if (!key || key.length < 8) return 'Not set';
        return `${key.substring(0, 4)}••••${key.substring(key.length - 4)}`;
    };

    const getShortName = (id: ChatModel) => {
        if (id.includes('flash-lite')) return 'Lite';
        if (id.includes('flash')) return 'Flash';
        if (id.includes('pro')) return 'Pro';
        const model = models.find(m => m.id === id);
        return model?.isCustom ? 'Custom' : 'Model';
    };

    const getModelIcon = (id: ChatModel) => {
        if (id.includes('flash-lite')) return LiteIcon;
        if (id.includes('pro')) return ProIcon;
        if (id.includes('flash')) return FlashIcon;
        return CustomModelIcon; 
    };

    const getModelColor = (id: ChatModel) => {
        if (id.includes('flash-lite')) return 'text-emerald-500';
        if (id.includes('pro')) return 'text-violet-600 dark:text-violet-400';
        if (id.includes('flash')) return 'text-amber-500';
        return 'text-blue-500';
    };

    const handleSaveModel = () => {
        if (newModelId && newModelName && onAddModel) {
            onAddModel(newModelId.trim(), newModelName.trim());
            setNewModelId('');
            setNewModelName('');
            setIsAddingModel(false);
        }
    };

    const SelectedIcon = getModelIcon(selectedChatModel);
    const selectedColor = getModelColor(selectedChatModel);

    return (
        <div ref={selectorRef} className="relative flex-shrink-0">
            <Tooltip content="Select AI Model" position="top" align="center" className="hidden md:block">
                <button
                    onClick={() => setIsOpen(prev => !prev)}
                    className={`
                        group flex items-center gap-2 pl-2.5 pr-2 py-1.5 rounded-full transition-all duration-200 border
                        ${isOpen 
                            ? 'bg-white dark:bg-[#2E2F33] border-neutral-200 dark:border-white/10 shadow-md' 
                            : 'bg-transparent border-transparent hover:bg-black/5 dark:hover:bg-white/10'
                        }
                    `}
                >
                    <SelectedIcon className={`w-4 h-4 ${selectedColor}`} />
                    <span className={`text-[11px] font-bold tracking-wide uppercase ${isOpen ? 'text-neutral-900 dark:text-white' : 'text-neutral-500 dark:text-neutral-400 group-hover:text-neutral-800 dark:group-hover:text-neutral-200'}`}>
                        {getShortName(selectedChatModel)}
                    </span>
                    <ChevronDown className={`w-3 h-3 text-neutral-400 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} />
                </button>
            </Tooltip>

            {isOpen && (
                <div 
                    className="absolute bottom-full mb-3 right-0 w-72 max-w-[calc(100vw-2rem)] bg-white/90 dark:bg-[#161618]/95 backdrop-blur-2xl border border-white/20 dark:border-white/10 rounded-2xl shadow-2xl overflow-hidden z-40 origin-bottom-right"
                >
                    {/* Header */}
                    <div className="px-4 py-3 border-b border-neutral-100 dark:border-white/5 bg-neutral-50/50 dark:bg-white/5 flex justify-between items-center">
                        <h4 className="text-xs font-bold text-neutral-500 dark:text-neutral-400 uppercase tracking-widest">
                            {isAddingModel ? 'Add Custom Model' : 'Intelligence Level'}
                        </h4>
                        {isAddingModel && (
                             <button onClick={() => setIsAddingModel(false)} className="p-1 rounded-full hover:bg-black/5 dark:hover:bg-white/10">
                                 <X className="w-3 h-3 text-neutral-500" />
                             </button>
                        )}
                    </div>

                    {/* Content */}
                    <div className="p-2 space-y-1">
                        {isAddingModel ? (
                            <div className="p-2 space-y-3">
                                <div>
                                    <label className="text-[10px] font-bold text-neutral-500 dark:text-neutral-400 uppercase mb-1 block">Model ID</label>
                                    <input 
                                        type="text" 
                                        value={newModelId}
                                        onChange={(e) => setNewModelId(e.target.value)}
                                        placeholder="e.g. gemini-1.5-pro-002"
                                        className="w-full bg-neutral-100 dark:bg-black/20 border border-neutral-200 dark:border-white/10 rounded-lg px-2 py-1.5 text-xs text-neutral-900 dark:text-white focus:outline-none focus:ring-1 focus:ring-amber-500"
                                        autoFocus
                                    />
                                </div>
                                <div>
                                    <label className="text-[10px] font-bold text-neutral-500 dark:text-neutral-400 uppercase mb-1 block">Display Name</label>
                                    <input 
                                        type="text" 
                                        value={newModelName}
                                        onChange={(e) => setNewModelName(e.target.value)}
                                        placeholder="e.g. Gemini 1.5 Pro Exp"
                                        className="w-full bg-neutral-100 dark:bg-black/20 border border-neutral-200 dark:border-white/10 rounded-lg px-2 py-1.5 text-xs text-neutral-900 dark:text-white focus:outline-none focus:ring-1 focus:ring-amber-500"
                                    />
                                </div>
                                <button 
                                    onClick={handleSaveModel}
                                    disabled={!newModelId || !newModelName}
                                    className="w-full bg-amber-600 hover:bg-amber-700 text-white rounded-lg py-2 text-xs font-bold transition-colors disabled:opacity-50"
                                >
                                    Save Model
                                </button>
                            </div>
                        ) : (
                            <>
                                {models.map(model => {
                                    const isSelected = selectedChatModel === model.id;
                                    const ItemIcon = getModelIcon(model.id);
                                    const itemColor = getModelColor(model.id);

                                    return (
                                        <div key={model.id} className="relative group/item">
                                            <button
                                                onClick={() => { onSelectChatModel(model.id); setIsOpen(false); }}
                                                className={`
                                                    w-full text-left p-3 rounded-xl transition-all duration-200 flex items-start gap-3 relative overflow-hidden
                                                    ${isSelected 
                                                        ? 'bg-neutral-100 dark:bg-white/10 shadow-inner' 
                                                        : 'hover:bg-neutral-50 dark:hover:bg-white/5'
                                                    }
                                                `}
                                            >
                                                {/* Selection Indicator Bar */}
                                                {isSelected && <div className="absolute left-0 top-3 bottom-3 w-1 bg-neutral-900 dark:bg-white rounded-r-full" />}

                                                <div className={`mt-0.5 p-2 rounded-lg bg-white dark:bg-black/20 shadow-sm flex-shrink-0 ${itemColor}`}>
                                                    <ItemIcon className="w-4 h-4" />
                                                </div>

                                                <div className="flex-1 min-w-0">
                                                    <div className="flex justify-between items-center mb-0.5">
                                                        <span className={`text-sm font-bold truncate ${isSelected ? 'text-neutral-900 dark:text-white' : 'text-neutral-700 dark:text-gray-300'}`}>
                                                            {model.name}
                                                        </span>
                                                        {isSelected && <CheckCircle2 className="h-4 w-4 text-neutral-900 dark:text-white flex-shrink-0" />}
                                                    </div>
                                                    <p className="text-[10px] font-medium text-neutral-500 dark:text-gray-400 leading-snug line-clamp-2">
                                                        {model.description}
                                                    </p>
                                                </div>
                                            </button>

                                            {/* Delete Button for Custom Models */}
                                            {model.isCustom && onDeleteModel && (
                                                <button 
                                                    onClick={(e) => { e.stopPropagation(); onDeleteModel(model.id); }}
                                                    className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-full opacity-0 group-hover/item:opacity-100 transition-opacity hover:scale-110"
                                                    title="Delete Model"
                                                >
                                                    <Trash2 className="w-3.5 h-3.5" />
                                                </button>
                                            )}
                                        </div>
                                    );
                                })}

                                {onAddModel && (
                                    <button 
                                        onClick={() => setIsAddingModel(true)}
                                        className="w-full flex items-center justify-center gap-2 p-2.5 rounded-xl border border-dashed border-neutral-300 dark:border-neutral-700 text-neutral-500 dark:text-neutral-400 hover:text-amber-600 dark:hover:text-amber-400 hover:border-amber-400 dark:hover:border-amber-500/50 hover:bg-amber-50 dark:hover:bg-amber-900/10 transition-all text-xs font-bold uppercase tracking-wide mt-2"
                                    >
                                        <Plus className="w-3.5 h-3.5" />
                                        Add Custom Model
                                    </button>
                                )}
                            </>
                        )}
                    </div>

                    {/* API Key Footer */}
                    <div className="p-2 border-t border-neutral-100 dark:border-white/5 bg-neutral-50/80 dark:bg-black/20">
                        <button
                            onClick={() => { onOpenApiKeyModal(); setIsOpen(false); }}
                            className="w-full flex items-center justify-between p-2.5 rounded-xl text-xs font-medium text-neutral-600 dark:text-gray-300 hover:bg-white dark:hover:bg-white/5 hover:shadow-sm transition-all border border-transparent hover:border-neutral-200 dark:hover:border-white/10"
                        >
                            <div className="flex items-center gap-2">
                                <Key className="w-3.5 h-3.5 text-neutral-400" />
                                <span>API Key</span>
                            </div>
                            <span className="font-mono text-[10px] opacity-60 bg-neutral-200 dark:bg-black/40 px-1.5 py-0.5 rounded text-neutral-600 dark:text-neutral-400">
                                {maskApiKey(apiKey)}
                            </span>
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

