import React, { useMemo } from 'react';
import { Transaction } from '../../types';
import { TrendingUp, TrendingDown, Calendar, Target } from 'lucide-react';

interface FinancialFitnessCardProps {
    transactions: Transaction[];
    budget: number;
}

const FinancialFitnessCard: React.FC<FinancialFitnessCardProps> = ({ transactions, budget }) => {
    const stats = useMemo(() => {
        const now = new Date();
        const totalDaysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
        const daysPassed = now.getDate();
        const daysRemaining = Math.max(1, totalDaysInMonth - daysPassed + 1); // Include today

        // Filter for this month only
        const thisMonthTransactions = transactions.filter(t => {
            const d = new Date(t.transaction_date);
            return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
        });

        // Calculate totals
        const income = thisMonthTransactions.filter(t => t.type === 'income').reduce((sum, t) => sum + Number(t.amount), 0);
        const expense = thisMonthTransactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + Number(t.amount), 0);

        // Use Budget if set, otherwise assume Income is the limit. Fallback to 0 if neither (but handle div by 0).
        const activeLimit = budget > 0 ? budget : income; 

        // 1. Daily Safe Spend
        // How much can I spend per day for the rest of the month to stay within limit?
        const remainingAmount = activeLimit - expense;
        let dailySafeLimit = 0;

        if (remainingAmount > 0) {
            dailySafeLimit = remainingAmount / daysRemaining;
        }

        // 2. Projected End of Month Status
        // Based on current burn rate, where will we land?
        const dailyBurnRate = daysPassed > 0 ? expense / daysPassed : 0;
        const projectedExpense = expense + (dailyBurnRate * (daysRemaining - 1)); // -1 because today is partly done/accounted in daily burn
        const projectedBalance = activeLimit - projectedExpense;

        let status: 'Saving' | 'OnTrack' | 'Overspending' = 'OnTrack';
        if (projectedBalance > (activeLimit * 0.1)) status = 'Saving'; // Saving > 10%
        else if (projectedBalance < 0) status = 'Overspending';

        return {
            dailySafeLimit,
            projectedBalance,
            daysRemaining,
            status,
            activeLimit
        };
    }, [transactions, budget]);

    // Theme logic based on status
    const theme = useMemo(() => {
        if (stats.status === 'Overspending') return { 
            bg: 'bg-gradient-to-br from-[#1a1a1a] to-[#2b1212]', 
            border: 'border-red-500/20',
            icon: TrendingDown,
            iconColor: 'text-red-500',
            labelColor: 'text-red-200',
            projectedLabel: 'Projected Deficit',
            highlight: 'text-red-400'
        };
        if (stats.status === 'Saving') return { 
            bg: 'bg-gradient-to-br from-[#1a1a1a] to-[#0f2e1f]', 
            border: 'border-emerald-500/20',
            icon: TrendingUp,
            iconColor: 'text-emerald-500',
            labelColor: 'text-emerald-200',
            projectedLabel: 'Projected Savings',
            highlight: 'text-emerald-400'
        };
        return { 
            bg: 'bg-gradient-to-br from-[#1a1a1a] to-[#1e293b]', 
            border: 'border-indigo-500/20',
            icon: Target,
            iconColor: 'text-indigo-400',
            labelColor: 'text-indigo-200',
            projectedLabel: 'Projected Balance',
            highlight: 'text-indigo-400'
        };
    }, [stats.status]);

    return (
        <div className={`relative w-full rounded-3xl overflow-hidden shadow-lg mb-6 border ${theme.border}`}>
            {/* Background */}
            <div className={`absolute inset-0 ${theme.bg}`}></div>

            {/* Content */}
            <div className="relative z-10 p-6 flex flex-col sm:flex-row items-stretch sm:items-center justify-between gap-6">

                {/* Section 1: Daily Safe Spend (Primary Actionable Metric) */}
                <div className="flex-1 flex flex-col justify-center">
                    <div className="flex items-center gap-2 mb-2 opacity-80">
                        <Calendar className="w-4 h-4 text-gray-400" />
                        <p className="text-xs font-bold uppercase tracking-widest text-gray-400">Daily Safe Limit</p>
                    </div>

                    <div className="flex items-baseline gap-1">
                        <h2 className={`text-4xl md:text-5xl font-extrabold tracking-tight text-white`}>
                            ₹{Math.floor(stats.dailySafeLimit).toLocaleString('en-IN')}
                        </h2>
                        <span className="text-sm font-medium text-gray-500">/ day</span>
                    </div>

                    <p className="text-xs text-gray-500 mt-2 font-medium">
                        For the next <span className="text-gray-300">{stats.daysRemaining} days</span> to hit your goal.
                    </p>
                </div>

                {/* Divider (Mobile Horizontal / Desktop Vertical) */}
                <div className="h-px sm:h-16 w-full sm:w-px bg-white/10"></div>

                {/* Section 2: Projection (Motivation/Warning) */}
                <div className="flex-shrink-0 min-w-[140px] flex flex-col justify-center">
                     <div className="flex items-center gap-2 mb-2 opacity-90">
                        <theme.icon className={`w-4 h-4 ${theme.iconColor}`} />
                        <p className={`text-xs font-bold uppercase tracking-widest ${theme.labelColor}`}>
                            {theme.projectedLabel}
                        </p>
                    </div>

                    <p className={`text-2xl font-bold ${theme.highlight}`}>
