import React, { useMemo } from 'react';
import { Transaction } from '../../types';
import { TrendingUp, AlertTriangle, CheckCircle2, Wallet } from 'lucide-react';

interface FinancialFitnessCardProps {
    transactions: Transaction[];
    budget: number;
}

const FinancialFitnessCard: React.FC<FinancialFitnessCardProps> = ({ transactions, budget }) => {
    const stats = useMemo(() => {
        const now = new Date();
        const totalDaysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
        const daysPassed = now.getDate();

        // Filter for this month only
        const thisMonthTransactions = transactions.filter(t => {
            const d = new Date(t.transaction_date);
            return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
        });

        // Calculate totals
        const income = thisMonthTransactions.filter(t => t.type === 'income').reduce((sum, t) => sum + Number(t.amount), 0);
        const expense = thisMonthTransactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + Number(t.amount), 0);

        // Active Limit: Budget if set, otherwise Income.
        const activeLimit = budget > 0 ? budget : income; 
        const remaining = Math.max(0, activeLimit - expense);

        // Percentages
        // Cap at 100 for the ring visual, but keep real % for text
        const rawPercent = activeLimit > 0 ? (expense / activeLimit) * 100 : 0;
        const visualPercent = Math.min(rawPercent, 100);

        // Time Progress
        const timePercent = (daysPassed / totalDaysInMonth) * 100;

        // Status Logic
        let status: 'safe' | 'warning' | 'danger' = 'safe';
        if (rawPercent > 100) status = 'danger';
        else if (rawPercent > 85) status = 'danger';
        else if (rawPercent > timePercent + 10) status = 'warning'; // Spending faster than time passing

        return {
            expense,
            activeLimit,
            remaining,
            rawPercent,
            visualPercent,
            timePercent,
            status
        };
    }, [transactions, budget]);

    // Dynamic Theme based on status
    const theme = useMemo(() => {
        if (stats.status === 'danger') return {
            stroke: 'text-rose-500',
