    const circumference = 2 * Math.PI * radius;
    const strokeDashoffset = circumference - (stats.visualPercent / 100) * circumference;

    return (
        <div className="relative w-full bg-[#111] dark:bg-black rounded-[2.5rem] p-6 shadow-2xl border border-white/5 overflow-hidden group">

            {/* Background Ambience */}
            <div className={`absolute top-0 right-0 w-64 h-64 bg-gradient-to-bl from-white/5 to-transparent rounded-bl-full pointer-events-none opacity-50`}></div>
            <div className={`absolute bottom-0 left-0 w-32 h-32 ${theme.bg} blur-3xl rounded-full pointer-events-none transition-colors duration-500`}></div>

            <div className="relative z-10 flex flex-col sm:flex-row items-center gap-8">

                {/* 1. The Radial Gauge */}
                <div className="relative flex items-center justify-center">
                    {/* Glow Effect behind ring */}
                    <div className={`absolute inset-0 rounded-full ${theme.bg} blur-xl opacity-20`}></div>

                    <svg className="transform -rotate-90 w-40 h-40 drop-shadow-xl">
                        {/* Background Track */}
                        <circle
                            cx="80"
                            cy="80"
                            r={radius}
                            stroke="currentColor"
                            strokeWidth="10"
                            fill="transparent"
                            className="text-white/10"
                        />
                        {/* Progress Bar */}
                        <circle
                            cx="80"
                            cy="80"
                            r={radius}
                            stroke="currentColor"
                            strokeWidth="10"
                            fill="transparent"
                            strokeDasharray={circumference}
                            strokeDashoffset={strokeDashoffset}
