import React, { useMemo } from 'react';
import { Transaction } from '../../types';
import { TrendingUp, TrendingDown, Calendar, AlertCircle, CheckCircle2 } from 'lucide-react';

interface FinancialFitnessCardProps {
    transactions: Transaction[];
    budget: number;
}

const FinancialFitnessCard: React.FC<FinancialFitnessCardProps> = ({ transactions, budget }) => {
    const stats = useMemo(() => {
        const now = new Date();
        const totalDaysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
        const daysPassed = now.getDate();
        const daysRemaining = Math.max(1, totalDaysInMonth - daysPassed + 1);

        // Filter for this month only
        const thisMonthTransactions = transactions.filter(t => {
            const d = new Date(t.transaction_date);
            return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
        });

        // Calculate totals
        const income = thisMonthTransactions.filter(t => t.type === 'income').reduce((sum, t) => sum + Number(t.amount), 0);
        const expense = thisMonthTransactions.filter(t => t.type === 'expense').reduce((sum, t) => sum + Number(t.amount), 0);

        // Active Limit: Budget if set, otherwise Income.
        const activeLimit = budget > 0 ? budget : income; 
        const remaining = activeLimit - expense;

        // 1. Daily Safe Spend
        // How much can I spend per day for the rest of the month?
        let dailySafeLimit = 0;
        if (remaining > 0) {
            dailySafeLimit = remaining / daysRemaining;
        }

        // 2. Pacing Logic (Time vs Money)
        const timeProgress = (daysPassed / totalDaysInMonth) * 100;
        const budgetProgress = activeLimit > 0 ? (expense / activeLimit) * 100 : 0;

        // Are we saving or overspending?
        // Saving = Budget consumed is LESS than Time passed
        const isSaving = budgetProgress < timeProgress;
        const diffPercent = Math.abs(timeProgress - budgetProgress);

        return {
            dailySafeLimit,
            remaining,
            activeLimit,
            timeProgress,
            budgetProgress,
            isSaving,
            diffPercent,
            daysRemaining
        };
    }, [transactions, budget]);

    return (
        <div className="w-full bg-white dark:bg-[#1e1f22] rounded-3xl p-6 border border-gray-200 dark:border-gray-800 shadow-sm mb-6 flex flex-col gap-6">

            {/* Top Row: Daily Limit & Status */}
