                <div>
                    <div className="flex items-center gap-2 mb-1">
                        <Calendar className="w-4 h-4 text-gray-400" />
                        <span className="text-xs font-bold uppercase tracking-widest text-gray-500">Daily Safe Limit</span>
                    </div>
                    <div className="flex items-baseline gap-1">
                        <span className="text-4xl font-extrabold text-gray-900 dark:text-white tracking-tight">
                            ₹{Math.floor(stats.dailySafeLimit).toLocaleString('en-IN')}
                        </span>
                        <span className="text-sm font-medium text-gray-500">/ day</span>
                    </div>
                    <p className="text-xs text-gray-500 mt-1">
                        To last the remaining {stats.daysRemaining} days.
                    </p>
                </div>

                <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full border ${
                    stats.isSaving 
                        ? 'bg-emerald-50 border-emerald-100 text-emerald-700 dark:bg-emerald-900/20 dark:border-emerald-900/50 dark:text-emerald-400' 
                        : 'bg-rose-50 border-rose-100 text-rose-700 dark:bg-rose-900/20 dark:border-rose-900/50 dark:text-rose-400'
                }`}>
                    {stats.isSaving ? <TrendingUp className="w-4 h-4" /> : <TrendingDown className="w-4 h-4" />}
                    <span className="text-xs font-bold">
                        {stats.isSaving ? 'Under Budget' : 'Over Budget'}
                    </span>
                </div>
            </div>

            {/* Middle Row: Progress Bar (Pacing) */}
            <div>
                <div className="flex justify-between text-xs font-medium mb-2">
                    <span className="text-gray-500">
                        Month Progress ({Math.round(stats.timeProgress)}%)
                    </span>
                    <span className={`${stats.isSaving ? 'text-emerald-600' : 'text-rose-600'}`}>
                        Budget Used ({Math.round(stats.budgetProgress)}%)
                    </span>
                </div>

                <div className="relative h-4 w-full bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden">
                    {/* Background Bar (Time Passed) - Neutral Marker */}
                    <div 
                        className="absolute top-0 bottom-0 left-0 bg-gray-200 dark:bg-gray-700 border-r-2 border-white dark:border-[#1e1f22] z-0" 
                        style={{ width: `${stats.timeProgress}%` }}
                    />

                    {/* Foreground Bar (Money Spent) */}
                    <div 
                        className={`absolute top-0 bottom-0 left-0 h-full rounded-full transition-all duration-1000 ease-out z-10 ${
                            stats.budgetProgress > 100 ? 'bg-red-600' :
                            stats.isSaving ? 'bg-emerald-500' : 'bg-rose-500'
                        }`}
                        style={{ width: `${Math.min(stats.budgetProgress, 100)}%` }}
                    />
                </div>

                {/* Insight Text */}
                <div className="mt-3 flex items-start gap-2 text-xs text-gray-500 dark:text-gray-400">
                    {stats.isSaving ? (
                        <CheckCircle2 className="w-4 h-4 text-emerald-500 flex-shrink-0" />
                    ) : (
                        <AlertCircle className="w-4 h-4 text-rose-500 flex-shrink-0" />
                    )}
                    <p>
                        {stats.isSaving 
                            ? `You are spending ${stats.diffPercent.toFixed(0)}% slower than time passing. Great job!` 
                            : `You are spending ${stats.diffPercent.toFixed(0)}% faster than time passing. Slow down slightly.`
                        }
                    </p>
                </div>
            </div>

            {/* Footer: Hard Numbers */}
            <div className="flex justify-between items-center pt-4 border-t border-gray-100 dark:border-gray-800">
                <div>
                    <p className="text-[10px] uppercase font-bold text-gray-400">Remaining</p>
                    <p className="text-sm font-bold text-gray-900 dark:text-white">₹{Math.floor(stats.remaining).toLocaleString('en-IN')}</p>
                </div>
                <div className="text-right">
                    <p className="text-[10px] uppercase font-bold text-gray-400">Monthly Limit</p>
                    <p className="text-sm font-bold text-gray-900 dark:text-white">₹{stats.activeLimit.toLocaleString('en-IN')}</p>
                </div>
            </div>

        </div>
    );
