// --- Improved Markdown <-> HTML Converters ---

const markdownToHtml = (markdown: string): string => {
    if (!markdown) return '';

    // 1. Protect Code Blocks: Extract them so we don't mess up their newlines
    const codeBlocks: string[] = [];
    let processed = markdown.replace(/```([\s\S]*?)```/gim, (match, code) => {
        codeBlocks.push(code); // Keep original code content
        return `___CODE_BLOCK_${codeBlocks.length - 1}___`;
    });

    let html = processed
        .replace(/^### (.*$)/gim, '<h3>$1</h3>')
        .replace(/^## (.*$)/gim, '<h2>$1</h2>')
        .replace(/^# (.*$)/gim, '<h1>$1</h1>')
        .replace(/^\> (.*$)/gim, '<blockquote>$1</blockquote>')
        // Lists
        .replace(/^\d+\.\s+(.*$)/gim, '<ol><li>$1</li></ol>') // Ordered
        .replace(/^\- (.*$)/gim, '<ul><li>$1</li></ul>') // Unordered
        // Separator
        .replace(/^(---|___|\*\*\*)\s*$/gim, '<hr>')
        // Formatting
        .replace(/\*\*(.*)\*\*/gim, '<b>$1</b>')
        .replace(/\*(.*)\*/gim, '<i>$1</i>')
        .replace(/~~(.*)~~/gim, '<s>$1</s>')
        // Inline Code
        .replace(/`([^`]+)`/gim, '<code>$1</code>')
        // Links
        .replace(/\[([^\]]+)\]\(([^)]+)\)/gim, '<a href="$2">$1</a>');

    // --- Table Processing ---
    // Detects blocks starting with | and containing |---| separator logic
    // Simplified regex to catch table-like blocks
    html = html.replace(/((?:^\|.*\|$\n?)+)/gm, (match) => {
        const lines = match.trim().split('\n');
        // Need at least header and separator
        if (lines.length < 2) return match; 

        // Basic check for separator line (must contain | and -)
        if (!lines[1].includes('|') || !lines[1].includes('-')) return match;

        let tableHtml = '<table class="w-full border-collapse my-4 table-auto">';

        // Header
        const headerCells = lines[0].split('|').filter(c => c.trim() !== '').map(c => c.trim());
        tableHtml += '<thead><tr>';
        headerCells.forEach(cell => {
             // Handle formatting inside cell headers recursively (simple bold/italic)
             let content = cell.replace(/\*\*(.*)\*\*/gim, '<b>$1</b>').replace(/\*(.*)\*/gim, '<i>$1</i>');
             tableHtml += `<th class="border px-4 py-2 bg-gray-100 dark:bg-gray-800 font-bold border-gray-300 dark:border-gray-700 text-left">${content}</th>`;
        });
        tableHtml += '</tr></thead><tbody>';

        // Rows (Skip index 1 which is separator |---|)
        for(let i = 2; i < lines.length; i++) {
             const rowCells = lines[i].split('|').filter(c => c.trim() !== '').map(c => c.trim());
             tableHtml += '<tr>';
             rowCells.forEach(cell => {
                 let content = cell.replace(/\*\*(.*)\*\*/gim, '<b>$1</b>').replace(/\*(.*)\*/gim, '<i>$1</i>');
                 tableHtml += `<td class="border px-4 py-2 border-gray-300 dark:border-gray-700">${content}</td>`;
             });
             tableHtml += '</tr>';
        }
        tableHtml += '</tbody></table>';
        return tableHtml;
    });

    // Merge adjacent lists
    html = html.replace(/<\/ul>\s*<ul>/gim, '');
    html = html.replace(/<\/ol>\s*<ol>/gim, '');

    // Clean up newlines around block elements to prevent double spacing with <br>
    // Remove newline AFTER block close
    html = html.replace(/(<\/h[1-6]>|<\/blockquote>|<\/ul>|<\/ol>|<hr>|<\/table>|___CODE_BLOCK_\d+___)\n/gim, '$1');
    // Remove newline BEFORE block open
    html = html.replace(/\n(___CODE_BLOCK_\d+___)/gim, '$1');

    // 2. Convert remaining newlines to <br>
    html = html.replace(/\n/gim, '<br>');

    // 3. Restore Code Blocks
    html = html.replace(/___CODE_BLOCK_(\d+)___/gim, (match, index) => {
        const codeContent = codeBlocks[parseInt(index, 10)];
        return `<pre>${codeContent}</pre>`;
    });

    return html;
};

const htmlToMarkdown = (html: string): string => {
    if (!html) return '';

    // 1. Clean up <br> tags related to divs to prevent double newlines
    let cleaned = html.replace(/<div[^>]*>\s*<br\s*\/?>/gim, '<div>');
    cleaned = cleaned.replace(/<br\s*\/?>\s*<\/div>/gim, '</div>');

    // Remove trailing <br> tags inside other block elements
    cleaned = cleaned.replace(/<br\s*\/?>\s*<\/(p|li|h[1-6]|pre)>/gim, '</$1>');

    // 2. Extract and format code blocks FIRST
    cleaned = cleaned.replace(/<pre>([\s\S]*?)<\/pre>/gim, (match, content) => {
        // Convert internal <br> to newlines for markdown code block
        let code = content.replace(/<br\s*\/?>/gim, '\n');
        // Decode basic HTML entities
        code = code.replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&');
        return `\n\`\`\`\n${code.trim()}\n\`\`\`\n`;
    });

    // 3. Handle Tables
    cleaned = cleaned.replace(/<table[^>]*>([\s\S]*?)<\/table>/gim, (match, content) => {
        let markdown = '\n';

        // Extract headers
        const headerMatch = content.match(/<thead>([\s\S]*?)<\/thead>/i);
        let columnCount = 0;

        if (headerMatch) {
             // Find th or td in head
             const ths = headerMatch[1].match(/<(?:th|td)[^>]*>(.*?)<\/(?:th|td)>/gim);
             if (ths) {
                 const headers = ths.map(th => {
                     // Strip bold/italic tags inside headers to clean up for markdown
                     let text = th.replace(/<\/?(?:th|td|b|strong|i|em)[^>]*>/gim, '').trim();
                     return text;
                 });
                 columnCount = headers.length;
                 markdown += '| ' + headers.join(' | ') + ' |\n';
                 markdown += '| ' + headers.map(() => ' :--- ').join(' | ') + ' |\n';
             }
        }

        // Extract rows
        const bodyMatch = content.match(/<tbody>([\s\S]*?)<\/tbody>/i);
        if (bodyMatch) {
            const trs = bodyMatch[1].match(/<tr[^>]*>([\s\S]*?)<\/tr>/gim);
            if (trs) {
                trs.forEach(tr => {
                    const tds = tr.match(/<td[^>]*>(.*?)<\/td>/gim);
                    if (tds) {
                         const cells = tds.map(td => {
                             // Handle inner bold/italic conversion locally or strip tags
                             let cellContent = td.replace(/<\/?td[^>]*>/gim, '').trim();
                             // Convert internal bold/italic HTML to markdown
                             cellContent = cellContent.replace(/<b>(.*?)<\/b>/gim, '**$1**').replace(/<strong>(.*?)<\/strong>/gim, '**$1**');
                             return cellContent;
                         });
                         // Fill missing columns if any
                         while (cells.length < columnCount) cells.push('');
                         markdown += '| ' + cells.join(' | ') + ' |\n';
                    }
                });
            }
        }

        return markdown + '\n';
    });

    // 4. Handle Lists specifically before generic tag stripping
    // Ordered Lists
    cleaned = cleaned.replace(/<ol>([\s\S]*?)<\/ol>/gim, (match, listContent) => {
        return listContent.replace(/<li>(.*?)<\/li>/gim, '1. $1\n');
    });
    // Unordered Lists
    cleaned = cleaned.replace(/<ul>([\s\S]*?)<\/ul>/gim, (match, listContent) => {
        return listContent.replace(/<li>(.*?)<\/li>/gim, '- $1\n');
    });
    // Cleanup list containers
    cleaned = cleaned.replace(/<\/?ol>/gim, '').replace(/<\/?ul>/gim, '');

    let md = cleaned
        .replace(/<h1>(.*?)<\/h1>/gim, '# $1\n')
        .replace(/<h2>(.*?)<\/h2>/gim, '## $1\n')
        .replace(/<h3>(.*?)<\/h3>/gim, '### $1\n')
        .replace(/<blockquote>(.*?)<\/blockquote>/gim, '> $1\n')
        .replace(/<b>(.*?)<\/b>/gim, '**$1**')
        .replace(/<strong>(.*?)<\/strong>/gim, '**$1**')
        .replace(/<i>(.*?)<\/i>/gim, '*$1*')
        .replace(/<em>(.*?)<\/em>/gim, '*$1*')
        .replace(/<s>(.*?)<\/s>/gim, '~~$1~~')
        .replace(/<strike>(.*?)<\/strike>/gim, '~~$1~~')
        .replace(/<hr\s*\/?>/gim, '\n---\n')
        .replace(/<code>(.*?)<\/code>/gim, '`$1`')
        .replace(/<a\s+(?:[^>]*?\s+)?href="([^"]*)"[^>]*>(.*?)<\/a>/gim, '[$2]($1)')

        // Block elements & spacing (divs often wrap lines)
        .replace(/<div[^>]*>/gim, '\n')
        .replace(/<\/div>/gim, '')
        .replace(/<p[^>]*>/gim, '\n')
        .replace(/<\/p>/gim, '\n')

        // Breaks
        .replace(/<br\s*\/?>/gim, '\n')
        .replace(/&nbsp;/gim, ' ');

    // Normalize newlines: 
    // Collapse sequences of 3 or more newlines into 2 (max one blank line)
    md = md.replace(/\n{3,}/g, '\n\n');

    return md.trim();
};

const NotesView: React.FC<NotesViewProps> = ({ user, onBack, searchQuery }) => {
    const [notes, setNotes] = useState<Note[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const { addToast } = useToast();

    // Editor/Detail View State
    const [selectedNote, setSelectedNote] = useState<Partial<Note> | null>(null);
    const [isVisible, setIsVisible] = useState(false);
    const [transformOrigin, setTransformOrigin] = useState<string>('center');
    const [showColorPicker, setShowColorPicker] = useState(false);
    const [noteToDelete, setNoteToDelete] = useState<string | null>(null);
    const [isReadOnly, setIsReadOnly] = useState(false);

    // Toolbar Active State
    const [activeFormats, setActiveFormats] = useState<ActiveFormats>({
        bold: false,
        italic: false,
        strikeThrough: false,
        blockType: 'p',
        isOrderedList: false,
        isUnorderedList: false,
    });

    const editorRef = useRef<HTMLDivElement>(null);
    const editorContainerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (!selectedNote) return;
        const adjustHeight = () => {
            if (editorContainerRef.current && window.visualViewport) {
                editorContainerRef.current.style.height = `${window.visualViewport.height}px`;
            }
        };
        if (window.visualViewport) {
            window.visualViewport.addEventListener('resize', adjustHeight);
            window.visualViewport.addEventListener('scroll', adjustHeight);
        }
        adjustHeight();
        return () => {
            if (window.visualViewport) {
                window.visualViewport.removeEventListener('resize', adjustHeight);
                window.visualViewport.removeEventListener('scroll', adjustHeight);
            }
        };
    }, [selectedNote]);

    useEffect(() => {
        loadNotes();
    }, [user]);

    const loadNotes = async () => {
        setIsLoading(true);
        try {
            const fetchedNotes = await getNotes(user);
            setNotes(fetchedNotes);
        } catch (e) {
            console.error("Failed to load notes", e);
        } finally {
            setIsLoading(false);
        }
    };

    const handleOpenNote = (note?: Note, e?: React.MouseEvent) => {
        if (e) {
            const rect = e.currentTarget.getBoundingClientRect();
            const originX = rect.left + rect.width / 2;
            const originY = rect.top + rect.height / 2;
            setTransformOrigin(`${originX}px ${originY}px`);
        } else {
            setTransformOrigin('center');
        }

        if (note) {
            setSelectedNote(note);
            setIsReadOnly(true); // Existing notes open in Read Only
        } else {
            setSelectedNote({
                id: crypto.randomUUID(),
                title: '',
                content: '',
                colorTheme: 'default',
                tags: [],
                isPinned: false
            });
            setIsReadOnly(false); // New notes open in Edit mode
        }
        setShowColorPicker(false);
        // Reset active formats when opening
        setActiveFormats({ bold: false, italic: false, strikeThrough: false, blockType: 'p', isOrderedList: false, isUnorderedList: false });
        requestAnimationFrame(() => setIsVisible(true));
    };

    const getEditorContent = () => {
        if (editorRef.current) {
            return htmlToMarkdown(editorRef.current.innerHTML);
        }
        return selectedNote?.content || '';
    };

    const handleCloseNote = async () => {
        const isNewNote = selectedNote && !notes.some(n => n.id === selectedNote.id);
        const currentContent = getEditorContent();

        if (isNewNote && (selectedNote.title || currentContent)) {
            const noteToSave: Partial<Note> = { 
                ...selectedNote, 
                content: currentContent 
            };
            await handleSaveNote(noteToSave);
            addToast('Note created.', 'success');
            setTimeout(() => {
                const newCardElement = document.getElementById(`note-${noteToSave.id}`);
                if (newCardElement) {
                    const rect = newCardElement.getBoundingClientRect();
                    const originX = rect.left + rect.width / 2;
                    const originY = rect.top + rect.height / 2;
                    setTransformOrigin(`${originX}px ${originY}px`);
                }
                setIsVisible(false);
            }, 50);
        } else {
            setIsVisible(false);
            if (selectedNote) {
                // Check if changes made to avoid unnecessary saves/toasts
                const original = notes.find(n => n.id === selectedNote.id);
                // Only save if NOT read only (meaning user deliberately entered edit mode) OR if it was a new note flow
                if (!isReadOnly && original && (original.content !== currentContent || original.title !== selectedNote.title || original.colorTheme !== selectedNote.colorTheme)) {
                    await handleSaveNote({ ...selectedNote, content: currentContent });
                    addToast('Note saved.', 'success');
                }
            }
        }
        setTimeout(() => {
            setSelectedNote(null);
            setShowColorPicker(false);
            setIsReadOnly(false);
        }, 700);
    };

    const handleSaveNote = async (noteData: Partial<Note>) => {
        if (!noteData.title?.trim() && !noteData.content?.trim()) {
            return;
        }

        const newNote: Note = {
            id: noteData.id || crypto.randomUUID(),
            user_id: user?.id,
            title: noteData.title || '',
            content: noteData.content || '',
            tags: noteData.tags || [],
            isPinned: noteData.isPinned || false,
            colorTheme: noteData.colorTheme || 'default',
            createdAt: noteData.createdAt || new Date().toISOString(),
            updatedAt: new Date().toISOString(),
        };

        setNotes(prev => {
            const existingIndex = prev.findIndex(n => n.id === newNote.id);
            if (existingIndex >= 0) {
                const updated = [...prev];
                updated[existingIndex] = newNote;
                return updated;
            }
            return [newNote, ...prev];
        });

        await saveNote(newNote, user);
    };

    const handleDeleteNote = async (id: string) => {
        setNotes(prev => prev.filter(n => n.id !== id));
        await deleteNote(id, user);
        addToast('Note deleted.', 'success');
        if (selectedNote?.id === id) {
            setIsVisible(false);
            setSelectedNote(null);
        }
    };

    const handleConfirmDelete = async () => {
        if (noteToDelete) {
            await handleDeleteNote(noteToDelete);
            setNoteToDelete(null);
        }
    };

    const handlePinNote = async (id: string, isPinned: boolean) => {
        const note = notes.find(n => n.id === id);
        if (note) {
            const updated = { ...note, isPinned, updatedAt: new Date().toISOString() };
            setNotes(prev => prev.map(n => n.id === id ? updated : n));
            await saveNote(updated, user);
            addToast(isPinned ? 'Note pinned.' : 'Note unpinned.', 'info');
        }
    };

    const checkFormats = () => {
        if (!document.queryCommandState) return;

        const blockType = document.queryCommandValue('formatBlock');

        setActiveFormats({
            bold: document.queryCommandState('bold'),
            italic: document.queryCommandState('italic'),
            strikeThrough: document.queryCommandState('strikeThrough'),
            blockType: blockType ? blockType.toLowerCase() : 'p',
            isOrderedList: document.queryCommandState('insertOrderedList'),
            isUnorderedList: document.queryCommandState('insertUnorderedList'),
        });
    };

    const execCmd = (command: string, value: string | undefined = undefined) => {
        // Toggle Logic for Block Elements
        if (command === 'formatBlock' && value) {
            const currentBlock = document.queryCommandValue('formatBlock');
            if (currentBlock && currentBlock.toLowerCase() === value.toLowerCase()) {
                document.execCommand('formatBlock', false, 'p');
                checkFormats();
                if (editorRef.current) editorRef.current.focus();
                return;
            }
        }

        // Standard execution
        document.execCommand(command, false, value);
        checkFormats();
        if (editorRef.current) {
            editorRef.current.focus();
        }
    };

    // Helper to prevent focus loss during toolbar interactions
    const handleFormat = (e: React.MouseEvent, command: string, value?: string) => {
        e.preventDefault();
        execCmd(command, value);
    };

    const filteredNotes = notes
        .filter(n => 
            n.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
            n.content.toLowerCase().includes(searchQuery.toLowerCase()) ||
            n.tags.some(t => t.toLowerCase().includes(searchQuery.toLowerCase()))
        )
        .sort((a, b) => {
            if (a.isPinned && !b.isPinned) return -1;
            if (!a.isPinned && b.isPinned) return 1;
            return new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime();
        });

    const getEditorBgClass = () => {
        const theme = selectedNote?.colorTheme || 'default';
        const colorObj = colorOptions.find(c => c.id === theme);
        return colorObj ? colorObj.bg : 'bg-white';
    };

    const getButtonStyle = (isActive: boolean) => {
        return isActive 
            ? 'bg-amber-100 text-amber-600 dark:bg-amber-900/40 dark:text-amber-400' 
            : 'text-neutral-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800';
    };

    const handleEditorClick = () => {
        if (isReadOnly) {
             addToast('Read-only mode. Tap "Enable Editing" to make changes.', 'info');
        }
    };

    useEffect(() => {
        if (selectedNote && editorRef.current) {
            // Only update innerHTML if it is empty to prevent cursor jumping
            if (editorRef.current.innerHTML === '') {
                editorRef.current.innerHTML = markdownToHtml(selectedNote.content || '');
            }
        }
    }, [selectedNote]);

    return (
        <main className="relative z-10 h-full overflow-y-auto bg-[#F2F4F7] dark:bg-[#0D1117] transition-colors scrollbar-hide pt-20 md:pt-24">

            <div className="max-w-[1600px] mx-auto p-3 md:p-6 min-h-[calc(100vh-140px)] flex flex-col">
                {isLoading ? (
                    <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-3 space-y-3">
                        {[...Array(6)].map((_, i) => (
                            <div key={i} className="h-40 rounded-3xl bg-white/50 dark:bg-white/5 animate-pulse mb-3" />
                        ))}
                    </div>
                ) : (
                    <>
                        {notes.length === 0 && !searchQuery && (
                            <div className="flex flex-col items-center justify-center flex-1 py-20 text-center opacity-60">
                                <div className="p-6 bg-white dark:bg-[#1e1f22] rounded-3xl shadow-sm mb-4">
                                    <LayoutGrid className="w-12 h-12 text-neutral-300 dark:text-neutral-700" />
                                </div>
                                <h3 className="text-xl font-bold text-neutral-800 dark:text-white">Your ideas live here</h3>
                                <p className="text-neutral-500 mt-2 max-w-xs">Tap "Create New Note" to get started.</p>
                            </div>
                        )}

                        <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-3 pb-2">
                            <button 
                                onClick={(e) => handleOpenNote(undefined, e)}
                                className="w-full rounded-3xl p-1 bg-gradient-to-br from-amber-400 via-orange-400 to-pink-500 shadow-sm hover:shadow-lg hover:-translate-y-1 transition-all duration-300 group text-left hidden sm:block h-[18vh] min-h-[140px]"
                            >
                                <div className="bg-white dark:bg-[#1e1f22] h-full w-full rounded-[1.3rem] p-4 flex flex-col gap-2 items-center justify-center">
                                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-amber-100 to-orange-100 dark:from-amber-900/30 dark:to-orange-900/30 flex items-center justify-center text-amber-600 dark:text-amber-400 group-hover:scale-110 transition-transform">
                                        <Plus className="w-5 h-5" />
                                    </div>
                                    <span className="font-bold text-sm text-neutral-800 dark:text-white">New Note</span>
                                </div>
                            </button>

                            {filteredNotes.map(note => (
                                <NoteCard 
                                    key={note.id} 
                                    note={note} 
                                    onClick={handleOpenNote}
                                    onDelete={(id) => setNoteToDelete(id)}
                                    onPin={handlePinNote}
                                />
                            ))}
                        </div>
                    </>
                )}
            </div>

            {/* Mobile/Floating Create Button */}
            <button 
                onClick={(e) => handleOpenNote(undefined, e)}
                className="fixed bottom-6 right-6 z-40 w-14 h-14 bg-amber-500 rounded-full text-white shadow-lg flex items-center justify-center hover:scale-110 hover:bg-amber-600 transition-all active:scale-95"
                title="Create New Note"
            >
                <Plus className="w-8 h-8" />
            </button>

            {/* FULL PAGE Editor via Portal with "Genie" Effect */}
            {selectedNote && createPortal(
                <div 
                    ref={editorContainerRef}
                    className={`fixed inset-0 z-[60] bg-white dark:bg-[#0D1117] flex flex-col 
                        transition-all duration-[700ms] ease-[cubic-bezier(0.22,1,0.36,1)]
                        ${isVisible 
                            ? 'opacity-100 scale-100 rounded-none' 
                            : 'opacity-0 scale-[0.01] rounded-[3rem]'
                        }
                    `}
                    style={{ 
                        height: '100%',
                        transformOrigin: transformOrigin
                    }}
                >

                    {/* Editor Header */}
                    <div className="flex-none h-16 px-4 md:px-6 flex items-center justify-between bg-white/80 dark:bg-[#0D1117]/80 backdrop-blur-xl border-b border-gray-100 dark:border-gray-800 z-20 transition-all">
                        <div className="flex-1 flex justify-start items-center">
                            <button 
                                onClick={handleCloseNote} 
                                className="group flex items-center gap-1.5 py-2 pr-3 -ml-2 text-neutral-600 dark:text-gray-300 hover:text-neutral-900 dark:hover:text-white rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-all"
                                aria-label="Go back"
                            >
                                <ChevronLeft className="w-5 h-5 group-hover:-translate-x-0.5 transition-transform" />
                                <span className="text-sm font-medium hidden sm:inline-block">Back</span>
                            </button>
                        </div>

                        <div className="flex-none flex flex-col items-center pointer-events-none">
                            <span className="text-[10px] font-bold uppercase tracking-widest text-neutral-400 dark:text-neutral-500 flex items-center gap-1.5">
                                {isReadOnly ? <Lock className="w-3 h-3" /> : <Clock className="w-3 h-3" />}
                                {isReadOnly ? 'Read Only' : (selectedNote.updatedAt ? new Date(selectedNote.updatedAt).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : 'New')}
                            </span>
                        </div>

                        <div className="flex-1 flex justify-end items-center">
                             {isReadOnly ? (
                                <button 
                                    onClick={() => setIsReadOnly(false)}
                                    className="px-5 py-2 bg-neutral-100 dark:bg-gray-800 text-neutral-700 dark:text-gray-300 font-semibold rounded-full text-xs shadow-sm hover:bg-neutral-200 dark:hover:bg-gray-700 hover:scale-105 active:scale-95 transition-all duration-200 flex items-center gap-2"
                                >
                                    <Edit2 className="w-3 h-3" /> Enable Editing
                                </button>
                             ) : (
                                <button 
                                    onClick={handleCloseNote}
                                    className="px-5 py-2 bg-neutral-900 dark:bg-white text-white dark:text-black font-semibold rounded-full text-xs shadow-md hover:shadow-lg hover:scale-105 active:scale-95 transition-all duration-200 flex items-center gap-2"
                                >
                                    <Check className="w-3 h-3" /> Done
                                </button>
                             )}
                        </div>
                    </div>

                    {/* Editor Content Area */}
                    <div className={`flex-1 overflow-y-auto ${getEditorBgClass()} dark:bg-transparent transition-colors`}>
                        <div className="max-w-3xl mx-auto min-h-full p-6 flex flex-col">
                            {/* Title */}
                            <input 
                                type="text" 
                                placeholder="Title" 
                                value={selectedNote.title || ''}
                                onChange={e => setSelectedNote(prev => ({ ...prev!, title: e.target.value }))}
                                disabled={isReadOnly}
                                className="text-3xl md:text-4xl font-bold bg-transparent border-none focus:outline-none text-neutral-900 dark:text-white w-full placeholder-neutral-400/50 mb-4 mt-2 disabled:cursor-default"
                            />

                            <style>
                                {`
                                    .editor-content { min-height: 50vh; outline: none; }
                                    .editor-content:empty:before { content: attr(placeholder); color: #9ca3af; pointer-events: none; display: block; }
                                    .editor-content p { margin-bottom: 0.5em; line-height: 1.6; }
                                    .editor-content h1 { font-size: 1.5em; font-weight: bold; margin-top: 1em; margin-bottom: 0.5em; }
                                    .editor-content h2 { font-size: 1.25em; font-weight: bold; margin-top: 1em; margin-bottom: 0.5em; }
                                    .editor-content h3 { font-size: 1.1em; font-weight: bold; margin-top: 0.8em; margin-bottom: 0.4em; }
                                    .editor-content ul { list-style-type: disc; padding-left: 1.5em; margin-bottom: 0.5em; }
                                    .editor-content ol { list-style-type: decimal; padding-left: 1.5em; margin-bottom: 0.5em; }
                                    .editor-content li { margin-bottom: 0.25em; }
                                    .editor-content blockquote { border-left: 3px solid #ccc; padding-left: 1em; font-style: italic; color: #666; margin-bottom: 0.5em; }
                                    .dark .editor-content blockquote { border-left-color: #555; color: #aaa; }
                                    .editor-content pre { background: #f4f4f4; padding: 0.75em; border-radius: 6px; font-family: monospace; font-size: 0.9em; margin-bottom: 0.5em; overflow-x: auto; }
                                    .dark .editor-content pre { background: #1e1e1e; border: 1px solid #333; }
                                    .editor-content code { background: #f4f4f4; padding: 0.1em 0.3em; border-radius: 3px; font-family: monospace; font-size: 0.9em; color: #d63384; }
                                    .dark .editor-content code { background: #333; color: #e0e0e0; }
                                    .editor-content a { color: #3b82f6; text-decoration: underline; cursor: pointer; }
                                    .dark .editor-content a { color: #60a5fa; }
                                    .editor-content hr { border: 0; border-top: 2px solid #ccc; margin: 1em 0; }
                                    .dark .editor-content hr { border-top-color: #555; }

                                    /* Table Styles */
                                    .editor-content table { width: 100%; border-collapse: collapse; margin-bottom: 1em; }
                                    .editor-content th, .editor-content td { border: 1px solid #ddd; padding: 8px; text-align: left; }
                                    .dark .editor-content th, .dark .editor-content td { border-color: #444; }
                                    .editor-content th { background-color: #f8f9fa; font-weight: bold; }
                                    .dark .editor-content th { background-color: #1f2937; }
                                `}
                            </style>
                            <div 
                                ref={editorRef}
                                contentEditable={!isReadOnly}
                                suppressContentEditableWarning
                                placeholder="Start typing..." 
                                className="flex-1 w-full bg-transparent border-none focus:outline-none text-lg text-neutral-800 dark:text-gray-200 pb-2 editor-content"
                                onKeyUp={checkFormats}
                                onMouseUp={checkFormats}
                                onClick={handleEditorClick}
                            />
                        </div>
                    </div>

                    {/* Editor Toolbar - Hide when Read Only */}
                    {!isReadOnly && (
                        <div className="flex-none p-3 border-t border-gray-100 dark:border-gray-800 bg-white/90 dark:bg-[#0D1117]/90 backdrop-blur-md z-20 pb-safe animate-slide-up-fade">
                            {showColorPicker && (
                                <div className="absolute bottom-full left-4 mb-3 p-2 bg-white dark:bg-[#1e1f22] rounded-2xl shadow-xl border border-gray-200 dark:border-gray-700 flex gap-1.5 z-30 animate-fade-in-up">
                                    {colorOptions.map(option => (
                                        <button
                                            key={option.id}
                                            onClick={() => { setSelectedNote(prev => ({ ...prev!, colorTheme: option.id })); setShowColorPicker(false); }}
                                            className={`w-8 h-8 rounded-full border-2 ${option.bg} ${option.border} flex items-center justify-center transition-transform hover:scale-110`}
                                        >
                                            {((selectedNote.colorTheme === option.id) || (!selectedNote.colorTheme && option.id === 'default')) && <Check className="w-4 h-4 text-black/50" />}
                                        </button>
                                    ))}
                                </div>
                            )}

                            <div className="flex items-center gap-2 max-w-3xl mx-auto">
                                <button 
                                    onClick={() => setShowColorPicker(!showColorPicker)}
                                    className={`p-2.5 rounded-xl hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors ${showColorPicker ? 'bg-gray-100 dark:bg-gray-800 text-amber-500' : 'text-neutral-500 dark:text-gray-400'}`}
                                >
                                    <Palette className="w-5 h-5" />
                                </button>

                                <div className="w-px h-6 bg-gray-200 dark:bg-gray-800 mx-1" />

                                <div className="flex-1 flex items-center gap-1 overflow-x-auto scrollbar-hide pr-2">
                                    <button onMouseDown={(e) => handleFormat(e, 'undo')} className="p-2.5 rounded-xl hover:bg-gray-100 dark:hover:bg-gray-800 text-neutral-500 dark:text-gray-400" title="Undo"><Undo className="w-4 h-4" /></button>
                                    <button onMouseDown={(e) => handleFormat(e, 'redo')} className="p-2.5 rounded-xl hover:bg-gray-100 dark:hover:bg-gray-800 text-neutral-500 dark:text-gray-400" title="Redo"><Redo className="w-4 h-4" /></button>
                                    <div className="w-px h-4 bg-gray-200 dark:bg-gray-800 mx-1" />

                                    <button onMouseDown={(e) => handleFormat(e, 'bold')} className={`p-2.5 rounded-xl transition-colors ${getButtonStyle(activeFormats.bold)}`} title="Bold"><Bold className="w-4 h-4" /></button>
                                    <button onMouseDown={(e) => handleFormat(e, 'italic')} className={`p-2.5 rounded-xl transition-colors ${getButtonStyle(activeFormats.italic)}`} title="Italic"><Italic className="w-4 h-4" /></button>
                                    <button onMouseDown={(e) => handleFormat(e, 'strikeThrough')} className={`p-2.5 rounded-xl transition-colors ${getButtonStyle(activeFormats.strikeThrough)}`} title="Strikethrough"><Strikethrough className="w-4 h-4" /></button>

                                    <button onMouseDown={(e) => handleFormat(e, 'formatBlock', 'H1')} className={`p-2.5 rounded-xl transition-colors ${getButtonStyle(activeFormats.blockType === 'h1')}`} title="Heading 1"><Heading1 className="w-4 h-4" /></button>
                                    <button onMouseDown={(e) => handleFormat(e, 'formatBlock', 'H2')} className={`p-2.5 rounded-xl transition-colors ${getButtonStyle(activeFormats.blockType === 'h2')}`} title="Heading 2"><Heading2 className="w-4 h-4" /></button>
                                    <button onMouseDown={(e) => handleFormat(e, 'formatBlock', 'H3')} className={`p-2.5 rounded-xl transition-colors ${getButtonStyle(activeFormats.blockType === 'h3')}`} title="Heading 3"><Heading3 className="w-4 h-4" /></button>

                                    <div className="w-px h-4 bg-gray-200 dark:bg-gray-800 mx-1" />

                                    <button onMouseDown={(e) => handleFormat(e, 'insertUnorderedList')} className={`p-2.5 rounded-xl transition-colors ${getButtonStyle(activeFormats.isUnorderedList)}`} title="List"><List className="w-4 h-4" /></button>
                                    <button onMouseDown={(e) => handleFormat(e, 'insertOrderedList')} className={`p-2.5 rounded-xl transition-colors ${getButtonStyle(activeFormats.isOrderedList)}`} title="Ordered List"><ListOrdered className="w-4 h-4" /></button>

                                    <button onMouseDown={(e) => handleFormat(e, 'formatBlock', 'blockquote')} className={`p-2.5 rounded-xl transition-colors ${getButtonStyle(activeFormats.blockType === 'blockquote')}`} title="Quote"><Quote className="w-4 h-4" /></button>
                                    <button onMouseDown={(e) => handleFormat(e, 'formatBlock', 'pre')} className={`p-2.5 rounded-xl transition-colors ${getButtonStyle(activeFormats.blockType === 'pre')}`} title="Code Block"><Code className="w-4 h-4" /></button>

                                    <button onMouseDown={(e) => handleFormat(e, 'insertHorizontalRule')} className="p-2.5 rounded-xl transition-colors text-neutral-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800" title="Separator"><Minus className="w-4 h-4" /></button>
                                </div>
                            </div>
                        </div>
                    )}
                </div>,
                document.body
            )}

            <ConfirmationModal
                isOpen={!!noteToDelete}
                onClose={() => setNoteToDelete(null)}
                onConfirm={handleConfirmDelete}
                title="Delete Note"
                message="Are you sure you want to permanently delete this note? This action cannot be undone."
                confirmButtonText="Delete"
                confirmButtonVariant="danger"
            />
        </main>
    );
};

export default NotesView;

import { Transaction, Note } from '../types';
import { getNotes, saveNote, getTransactions, getFinanceProfiles } from './dbService';
import { User } from '@supabase/supabase-js';

const LINK_TAG_PREFIX = 'wallet:';

/**
 * Helper to get the specific tag string for a wallet profile.
 */
const getWalletTag = (profileId: string | undefined | null) => {
    return `${LINK_TAG_PREFIX}${profileId || 'default'}`;
};

/**
 * Links a wallet (profile) to a specific note ID by adding a special tag to the note.
 * Removes the tag from any other notes to ensure a 1:1 mapping for this wallet.
 */
export const linkWalletToNote = async (user: User | null, profileId: string | null, note: Note) => {
    const targetTag = getWalletTag(profileId);
    const allNotes = await getNotes(user);

    // 1. Remove this wallet tag from ANY other notes to ensure uniqueness
    const oldLinkedNotes = allNotes.filter(n => n.tags?.includes(targetTag) && n.id !== note.id);

    for (const oldNote of oldLinkedNotes) {
        const newTags = (oldNote.tags || []).filter(t => t !== targetTag);
        await saveNote({ ...oldNote, tags: newTags, updatedAt: new Date().toISOString() }, user);
    }

    // 2. Add the tag to the target note if not present
    if (!note.tags?.includes(targetTag)) {
        const newTags = [...(note.tags || []), targetTag];
        await saveNote({ ...note, tags: newTags, updatedAt: new Date().toISOString() }, user);
    }
};

/**
 * Fetch the actual Note object linked to the current profile by looking for the tag.
 */
export const fetchLinkedNote = async (user: User | null, profileId: string | undefined | null): Promise<Note | undefined> => {
    const targetTag = getWalletTag(profileId);
    const allNotes = await getNotes(user);

    const candidates = allNotes.filter(n => n.tags?.includes(targetTag));
    return candidates.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())[0];
};

// --- NATURAL LANGUAGE GENERATION ---

const formatCurrency = (amount: number) => `₹${amount.toLocaleString('en-IN')}`;

const cleanText = (str: string) => {
    if (!str) return '';
    return str.replace(/[*_`\[\]~]/g, '').trim();
};

/**
 * Generates a structured, natural language line for the note.
 */
const generateLogLine = (t: Transaction): string => {
    const dateObj = new Date(t.transaction_date);
    const timeStr = dateObj.toLocaleTimeString('en-US', { 
        hour: '2-digit', 
        minute: '2-digit', 
        hour12: true 
    }).replace(/\s+/g, ' ').trim();

    // Dynamic Styles
    let amountClass = 'text-gray-900 dark:text-gray-100';
    let iconClass = 'fi-expense text-gray-500'; // Default

    // Category Code-Pill Styles
    let catBg = 'bg-gray-100 dark:bg-gray-800';
    let catText = 'text-gray-700 dark:text-gray-300';
    let catBorder = 'border-gray-200 dark:border-gray-700';

    if (t.type === 'income') {
        amountClass = 'text-emerald-600 dark:text-emerald-400';
        iconClass = 'fi-income text-emerald-500';

        catBg = 'bg-emerald-100 dark:bg-emerald-900/40';
        catText = 'text-emerald-800 dark:text-emerald-300';
        catBorder = 'border-emerald-200 dark:border-emerald-800/50';

    } else if (t.type === 'expense') {
        amountClass = 'text-rose-600 dark:text-rose-400';
        iconClass = 'fi-expense text-rose-500';

        catBg = 'bg-rose-100 dark:bg-rose-900/40';
        catText = 'text-rose-800 dark:text-rose-300';
        catBorder = 'border-rose-200 dark:border-rose-800/50';

    } else {
        amountClass = 'text-indigo-600 dark:text-indigo-400';
        iconClass = 'fi-transfer text-indigo-500';

        catBg = 'bg-indigo-100 dark:bg-indigo-900/40';
        catText = 'text-indigo-800 dark:text-indigo-300';
        catBorder = 'border-indigo-200 dark:border-indigo-800/50';
    }

    const iconHtml = `<span class="f-icon ${iconClass}"></span>`;

    // Styled Components for Markdown
    const amountHtml = `<span class="${amountClass} font-mono font-bold tracking-tight">${formatCurrency(t.amount)}</span>`;
    const timeHtml = `<span class="text-[10px] text-gray-400 dark:text-gray-500 font-mono ml-2 opacity-60">${timeStr}</span>`;

    // Updated Category HTML to mimic code block/pill style with specific colors
    const categoryHtml = `<span class="px-1.5 py-0.5 rounded-[4px] text-[11px] font-mono font-bold tracking-wide border ${catBorder} ${catBg} ${catText}">${cleanText(t.category)}</span>`;

    // Description in muted styling
    const descriptionClean = cleanText(t.description || '');
    let descHtml = '';

    if (descriptionClean && descriptionClean.toLowerCase() !== t.category.toLowerCase()) {
        descHtml = ` <span class="text-gray-500 dark:text-gray-400 text-xs">— ${descriptionClean}</span>`;
    }

    // High value alert
    const isHighValue = t.amount >= 5000;
    const alert = isHighValue ? '<span class="f-icon fi-alert text-amber-500"></span> ' : '';

    return `- ${alert}${iconHtml} ${categoryHtml} &nbsp;${amountHtml} ${descHtml} ${timeHtml} <!-- tx_id:${t.id} ts:${dateObj.getTime()} -->`;
};

const generateBaseDateHeader = (isoDate: string): string => {
    const dateObj = new Date(isoDate);
    const options: Intl.DateTimeFormatOptions = { weekday: 'long', month: 'short', day: 'numeric' };
    const dateStr = dateObj.toLocaleDateString('en-US', options);
    // Styled Date Header with Calendar Icon
    return `### <span class="f-icon fi-calendar text-gray-500"></span> <span class="text-gray-800 dark:text-gray-200">${dateStr}</span>`;
};

const parseLineStats = (line: string) => {
    const amountMatch = line.match(/₹([\d,]+)/);
    const amount = amountMatch ? parseInt(amountMatch[1].replace(/,/g, ''), 10) : 0;

    let type: 'income' | 'expense' | 'transfer' | 'unknown' = 'unknown';
    // Check for specific icon classes in the HTML string
    if (line.includes('fi-income')) type = 'income';
    else if (line.includes('fi-expense')) type = 'expense';
    else if (line.includes('fi-transfer')) type = 'transfer';
    // Fallback for backward compatibility with emojis
    else if (line.includes('💰')) type = 'income';
    else if (line.includes('💸')) type = 'expense';
    else if (line.includes('🔄')) type = 'transfer';

    return { type, amount };
};

const generateFooterStats = (txLines: string[]): string => {
    let income = 0;
    let expense = 0;

    txLines.forEach(line => {
        const { type, amount } = parseLineStats(line);
        if (type === 'income') income += amount;
        if (type === 'expense') expense += amount;
    });

    if (income === 0 && expense === 0) return '';

    const balance = income - expense;
    const sign = balance >= 0 ? '+' : '-';

    const incomePart = `<span class="f-icon fi-income text-emerald-500"></span> <span class="text-emerald-600 dark:text-emerald-400 font-mono font-bold text-xs">₹${income.toLocaleString('en-IN')}</span>`;
    const expensePart = `<span class="f-icon fi-expense text-rose-500"></span> <span class="text-rose-600 dark:text-rose-400 font-mono font-bold text-xs">₹${expense.toLocaleString('en-IN')}</span>`;
    const balancePart = `<span class="f-icon fi-wallet text-gray-800 dark:text-gray-200"></span> <span class="text-gray-900 dark:text-white font-mono font-extrabold text-xs">${sign}₹${Math.abs(balance).toLocaleString('en-IN')}</span>`;

    // Structured Blockquote Footer with Small, Normal Font. Wrapped in not-italic to override blockquote default.
    return `> <span class="not-italic"><span class="text-[10px] text-gray-400 dark:text-gray-500 font-bold uppercase tracking-wider">Daily Total</span> &nbsp; ${incomePart} &nbsp;<span class="text-gray-300 dark:text-gray-600 text-[10px]">|</span>&nbsp; ${expensePart} &nbsp;<span class="text-gray-300 dark:text-gray-600 text-[10px]">|</span>&nbsp; ${balancePart}</span> <!-- daily_stats -->`;
};

/**
 * Creates a text-based visual bar for the chart (e.g. ▓▓▓▓░░)
 */
const generateVisualBar = (value: number, total: number, colorClass: string) => {
    const maxBars = 10;
    const percent = total > 0 ? value / total : 0;
    const filledCount = Math.round(percent * maxBars);
    const emptyCount = maxBars - filledCount;

    const filled = '█'.repeat(filledCount);
    const empty = '░'.repeat(emptyCount);

    return `<span class="${colorClass} text-[10px]">${filled}</span><span class="text-gray-200 dark:text-gray-700 text-[10px]">${empty}</span>`;
};

/**
 * Generates a Dashboard Snapshot header for the top of the note as a Markdown Table.
