        `</div>` +
    `</div>`;

    // Construct the string with minimal newlines to control spacing perfectly
    return `<h1 class="text-xl font-bold text-gray-900 dark:text-white mb-1 flex items-center gap-2"><span class="text-2xl">🪙</span> ${profileName} Report</h1>` +
