    let income = 0;
    let expense = 0;
    let highestTx = 0;
    const catTotals: Record<string, number> = {};

    transactions.forEach(t => {
        const amt = Number(t.amount);
        if (amt > highestTx) highestTx = amt;

        if (t.type === 'income') income += amt;
        if (t.type === 'expense') {
            expense += amt;
            catTotals[t.category] = (catTotals[t.category] || 0) + amt;
        }
    });

    const balance = income - expense;
    const sign = balance >= 0 ? '+' : '-';
    const dateStr = new Date().toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' });

    // --- Insights Calculations ---
    const sortedCats = Object.entries(catTotals)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 5); // Top 5 Categories

    // Savings Rate Calculation
    let savingsRate = 0;
    if (income > 0) {
        savingsRate = ((income - expense) / income) * 100;
    }

    // Avg Transaction Calculation
    const expenseTxCount = transactions.filter(t => t.type === 'expense').length;
    const avgTx = expenseTxCount > 0 ? (expense / expenseTxCount) : 0;
    const dailyAvg = expense / 30; // Approx

    // --- GENERATE TABLES ---

    // 1. Category Breakdown Table with Visual Bars
    // | Category | Trend | Amount | % |
    const maxCatValue = sortedCats.length > 0 ? sortedCats[0][1] : 1; // Use highest category as denominator for relative bars

    let breakdownRows = "";
    if (sortedCats.length === 0) {
        breakdownRows = "| *No expenses recorded yet* | | | |";
    } else {
        breakdownRows = sortedCats.map(([cat, amount]) => {
