        loadData();
        refreshLinkedNote();
    }, [activeProfile.id]);

    // Re-load vehicles whenever the modal closes (in case they updated)
    useEffect(() => {
        if (!isVehicleManagerOpen) {
            loadVehicles();
        }
    }, [isVehicleManagerOpen]);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
