                onConfirm={executeDelete}
                title="Delete Transaction"
                message="Are you sure you want to permanently delete this transaction? This action cannot be undone."
                confirmButtonText="Delete"
                confirmButtonVariant="danger"
            />

            <ConfirmationModal
                isOpen={isBulkDeleteConfirmOpen}
                onClose={() => setIsBulkDeleteConfirmOpen(false)}
                onConfirm={executeBulkDelete}
                title={`Delete ${selectedIds.size} Transactions?`}
                message="This action cannot be undone. These records will be permanently removed."
                confirmButtonText="Delete All"
                confirmButtonVariant="danger"
            />

            <ConfirmationModal
                isOpen={!!profileToDelete}
                onClose={() => setProfileToDelete(null)}
                onConfirm={handleDeleteProfile}
                title="Delete Wallet?"
                message="Are you sure you want to permanently delete this wallet? All transactions inside it will also be lost."
                confirmButtonText="Delete Forever"
                confirmButtonVariant="danger"
            />
        </>
    );
};

export default FinanceView;

import React, { useState, useEffect, useRef } from 'react';
import { Transaction, TransactionLocation, Vehicle } from '../../types';
import { 
    X, Save, Calendar, Clock, Tag, CreditCard, AlignLeft, IndianRupee, ChevronDown, 
    Smartphone, Plus, Grid, Landmark, CheckCircle2, Search, MapPin, Navigation, Globe,
    Car, Bike, Fuel
} from 'lucide-react';
import type { User } from '@supabase/supabase-js';
import { CATEGORY_CONFIG } from './categories';
import LocationPickerMap from './LocationPickerMap';
import { getAddressFromCoordinates } from '../../services/locationService';

interface TransactionModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (t: Transaction) => void;
    initialData: Transaction | null;
    user: User | null;
    vehicles?: Vehicle[];
}

const PAYMENT_METHODS = [
    { id: 'Online', label: 'Online / UPI', icon: Smartphone, color: 'text-blue-500', bg: 'bg-blue-100 dark:bg-blue-900/30' },
    { id: 'Cash', label: 'Cash', icon: IndianRupee, color: 'text-green-500', bg: 'bg-green-100 dark:bg-green-900/30' },
    { id: 'Card', label: 'Card', icon: CreditCard, color: 'text-purple-500', bg: 'bg-purple-100 dark:bg-purple-900/30' },
    { id: 'Bank', label: 'Bank Transfer', icon: Landmark, color: 'text-gray-500', bg: 'bg-gray-100 dark:bg-gray-800' },
];

const TransactionModal: React.FC<TransactionModalProps> = ({ isOpen, onClose, onSave, initialData, user, vehicles = [] }) => {
    const [description, setDescription] = useState('');
    const [amount, setAmount] = useState('');
    const [type, setType] = useState<'expense' | 'income' | 'transfer'>('expense');
    const [category, setCategory] = useState('');
    const [method, setMethod] = useState('Online');
    const [isCustomCategory, setIsCustomCategory] = useState(false);

    // Location State
    const [location, setLocation] = useState<TransactionLocation | undefined>(undefined);
    const [isMapOpen, setIsMapOpen] = useState(false);

    // Vehicle & Fuel State
    const [selectedVehicleId, setSelectedVehicleId] = useState<string>('');
    const [kmDriven, setKmDriven] = useState('');
    const [fuelQuantity, setFuelQuantity] = useState(''); // Liters

    // UI State
    const [showAllCategories, setShowAllCategories] = useState(false);
    const [categorySearchQuery, setCategorySearchQuery] = useState('');
    const [isPaymentSelectorOpen, setIsPaymentSelectorOpen] = useState(false);

    // Initialize with local date strings
    const [date, setDate] = useState(() => {
        const now = new Date();
        const year = now.getFullYear();
        const month = String(now.getMonth() + 1).padStart(2, '0');
        const day = String(now.getDate()).padStart(2, '0');
        return `${year}-${month}-${day}`;
    });

    const [time, setTime] = useState(() => {
        const now = new Date();
        const hours = String(now.getHours()).padStart(2, '0');
        const minutes = String(now.getMinutes()).padStart(2, '0');
        return `${hours}:${minutes}`;
    });

    const dateInputRef = useRef<HTMLInputElement>(null);
    const timeInputRef = useRef<HTMLInputElement>(null);
    const categorySearchRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (showAllCategories && categorySearchRef.current) {
            categorySearchRef.current.focus();
        }
    }, [showAllCategories]);

    useEffect(() => {
        if (initialData) {
            setDescription(initialData.description);
            setAmount(initialData.amount.toString());
            setType(initialData.type);
            setCategory(initialData.category);
            setMethod(initialData.payment_method);
            setLocation(initialData.location);

            // Hydrate metadata
            if (initialData.metadata) {
                setSelectedVehicleId(initialData.metadata.vehicle_id || '');
                setKmDriven(initialData.metadata.km_driven?.toString() || '');
                setFuelQuantity(initialData.metadata.fuel_quantity?.toString() || '');
            }

            const list = CATEGORY_CONFIG[initialData.type];
            const isPredefined = list.some(c => c.id === initialData.category);
            setIsCustomCategory(!isPredefined);

            const d = new Date(initialData.transaction_date);
            const year = d.getFullYear();
            const month = String(d.getMonth() + 1).padStart(2, '0');
            const day = String(d.getDate()).padStart(2, '0');
            const hours = String(d.getHours()).padStart(2, '0');
            const minutes = String(d.getMinutes()).padStart(2, '0');

            setDate(`${year}-${month}-${day}`);
            setTime(`${hours}:${minutes}`);
