    let visibleCategories = [...defaultTop3];
    if (category && !isCustomCategory) {
        const isDefaultVisible = defaultTop3.some(c => c.id === category);
        if (!isDefaultVisible) {
            const selectedCatObj = allTypeCategories.find(c => c.id === category);
