                {cat.label}
            </span>
        </button>
    );

    const selectedPaymentMethod = PAYMENT_METHODS.find(m => m.id === method) || PAYMENT_METHODS[0];
    const PaymentIcon = selectedPaymentMethod.icon;

    const showFuelInputs = category === 'Fuel' && type === 'expense';

