                    <div className="px-6 py-4 border-b border-gray-200 dark:border-white/10 flex items-center justify-between bg-white/50 dark:bg-white/5 backdrop-blur-md">
                        <div>
                            <h3 className="font-bold text-lg text-gray-900 dark:text-white">All Categories</h3>
                            <p className="text-xs text-gray-500 dark:text-gray-400">Select one to continue</p>
                        </div>
                        <button onClick={() => setShowAllCategories(false)} className="p-2 rounded-full bg-gray-200 dark:bg-white/10 hover:bg-gray-300 dark:hover:bg-white/20 transition-colors">
                            <X className="w-5 h-5" />
                        </button>
                    </div>

                    {/* Search Bar in Category Modal */}
                    <div className="px-6 py-3 border-b border-gray-200/50 dark:border-white/5">
                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                            <input 
                                ref={categorySearchRef}
                                type="text"
                                value={categorySearchQuery}
                                onChange={(e) => setCategorySearchQuery(e.target.value)}
                                placeholder="Search categories..."
                                className="w-full pl-10 pr-4 py-2.5 rounded-xl bg-gray-100 dark:bg-black/30 border-none outline-none focus:ring-2 focus:ring-indigo-500/50 text-sm text-gray-900 dark:text-white placeholder-gray-400 transition-all"
                            />
                        </div>
                    </div>

                    <div className="p-6 overflow-y-auto grid grid-cols-4 sm:grid-cols-5 gap-4 content-start">
                        {filteredCategories.length > 0 ? (
                            filteredCategories.map(cat => renderCategoryButton(cat, true))
                        ) : (
                            <div className="col-span-full flex flex-col items-center justify-center py-10 text-gray-400 dark:text-gray-600">
                                <p className="text-sm">No categories found.</p>
                                <button 
                                    onClick={() => { setIsCustomCategory(true); setCategory(categorySearchQuery); setShowAllCategories(false); setCategorySearchQuery(''); }}
                                    className="mt-2 text-indigo-500 font-bold text-xs hover:underline"
                                >
                                    Use "{categorySearchQuery}" as custom
                                </button>
                            </div>
                        )}
                    </div>
                </div>
            )}

            {/* Payment Method Selector Modal Overlay */}
            {isPaymentSelectorOpen && (
                <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
                    <div 
                        className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity" 
                        onClick={() => setIsPaymentSelectorOpen(false)} 
                    />
                    <div className="relative w-full max-w-sm bg-white dark:bg-[#1e1f22] rounded-2xl shadow-xl overflow-hidden animate-fade-in-up">
                        <div className="p-4 border-b border-gray-100 dark:border-gray-800 flex justify-between items-center">
                            <h3 className="font-bold text-gray-900 dark:text-white">Payment Method</h3>
                            <button onClick={() => setIsPaymentSelectorOpen(false)} className="p-1 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors">
                                <X className="w-5 h-5 text-gray-500" />
                            </button>
                        </div>
                        <div className="p-2">
                            {PAYMENT_METHODS.map((m) => {
                                const Icon = m.icon;
                                return (
                                    <button
                                        key={m.id}
                                        type="button"
                                        onClick={() => { setMethod(m.id); setIsPaymentSelectorOpen(false); }}
                                        className="w-full flex items-center gap-3 px-4 py-3 text-sm font-medium text-gray-900 dark:text-white hover:bg-gray-50 dark:hover:bg-white/5 transition-colors rounded-xl text-left mb-1"
                                    >
                                        <div className={`p-2 rounded-lg ${m.bg}`}>
                                            <Icon className={`w-5 h-5 ${m.color}`} />
                                        </div>
                                        <span className="flex-1">{m.label}</span>
                                        {method === m.id && <CheckCircle2 className="w-5 h-5 text-indigo-500" />}
                                    </button>
                                );
                            })}
                        </div>
                    </div>
                </div>
            )}

            {/* Map Picker Modal Overlay */}
            {isMapOpen && (
                <LocationPickerMap 
                    initialLat={location?.lat}
                    initialLng={location?.lng}
                    onLocationSelect={handleMapSelection}
                    onClose={() => setIsMapOpen(false)}
                />
            )}
        </div>
    );
};

export default TransactionModal;

import React, { useRef, useMemo, useState, useEffect } from 'react';
import { Transaction } from '../../types';
import { 
    IndianRupee, Check, HelpCircle, Loader2, ArrowDownLeft, ArrowUpRight, Car, Fuel
} from 'lucide-react';
import { CATEGORY_CONFIG } from './categories';

interface TransactionListProps {
    transactions: Transaction[];
    onDelete: (id: string) => void;
    onEdit: (t: Transaction) => void;
    onView: (t: Transaction) => void;

    // Selection Props
    isSelectionMode?: boolean;
    selectedIds?: Set<string>;
    onToggleSelection?: (id: string) => void;
    onLongPress?: (id: string) => void;
}

const CategoryIcon: React.FC<{ categoryId: string, type: string, className?: string }> = ({ categoryId, type, className }) => {
    // Lookup the icon from our central config
    const configList = CATEGORY_CONFIG[type as keyof typeof CATEGORY_CONFIG] || CATEGORY_CONFIG.expense;
    const categoryData = configList.find(c => c.id === categoryId);

    if (categoryData) {
        const IconComponent = categoryData.icon;
        return <IconComponent className={className} />;
    }

    // Fallback for custom categories
    return <HelpCircle className={className} />;
}

const TransactionList: React.FC<TransactionListProps> = ({ 
    transactions, 
    onView,
    isSelectionMode,
    selectedIds,
    onToggleSelection,
    onLongPress
}) => {
    // Optimization 1: Memoize grouping logic to prevent heavy calculation on every render
    const grouped = useMemo(() => {
        return transactions.reduce((acc, t) => {
            const date = new Date(t.transaction_date).toDateString();
            if (!acc[date]) acc[date] = [];
            acc[date].push(t);
            return acc;
        }, {} as Record<string, Transaction[]>);
    }, [transactions]);

    // Optimization 2: Lazy Loading State
    const [displayLimit, setDisplayLimit] = useState(15); // Initial number of days/groups to show
    const observerTarget = useRef<HTMLDivElement>(null);

    const dateKeys = useMemo(() => Object.keys(grouped), [grouped]);
    const visibleKeys = dateKeys.slice(0, displayLimit);
    const hasMore = displayLimit < dateKeys.length;

    // Reset pagination when filters change (transactions prop changes)
    useEffect(() => {
        setDisplayLimit(15);
    }, [transactions]);

    // Optimization 3: Intersection Observer for Infinite Scroll
    useEffect(() => {
        const observer = new IntersectionObserver(
            (entries) => {
                if (entries[0].isIntersecting && hasMore) {
                    setDisplayLimit((prev) => prev + 10); // Load 10 more days at a time
                }
            },
            { threshold: 0.1, rootMargin: '200px' } // Load before reaching exact bottom
        );

        if (observerTarget.current) {
            observer.observe(observerTarget.current);
        }

        return () => observer.disconnect();
    }, [hasMore, dateKeys.length]);

    // Refs for Long Press Logic
    const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const isLongPressTriggered = useRef(false);

    const handlePointerDown = (id: string) => {
        if (isSelectionMode) return; 

        isLongPressTriggered.current = false;
        timerRef.current = setTimeout(() => {
            isLongPressTriggered.current = true;
            if (onLongPress) onLongPress(id);
        }, 500); 
    };

    const handlePointerUp = () => {
        if (timerRef.current) {
            clearTimeout(timerRef.current);
            timerRef.current = null;
        }
    };

    const handleClick = (t: Transaction) => {
        if (isLongPressTriggered.current) {
            isLongPressTriggered.current = false;
            return;
        }
        if (isSelectionMode && onToggleSelection) {
            onToggleSelection(t.id);
        } else {
            onView(t);
        }
    };

    if (transactions.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center py-20 opacity-50">
                <div className="p-6 bg-gray-100 dark:bg-gray-800 rounded-full mb-4">
                    <IndianRupee className="w-10 h-10 text-gray-400" />
                </div>
                <p className="text-gray-500 dark:text-gray-400 font-medium">No transactions found.</p>
            </div>
        );
    }

    return (
        <div className="space-y-8 select-none">
            {visibleKeys.map(dateStr => {
                const dayTransactions = grouped[dateStr];

                // Calculate daily totals
                const dailyIncome = dayTransactions
                    .filter(t => t.type === 'income')
                    .reduce((sum, t) => sum + Number(t.amount), 0);

                const dailyExpense = dayTransactions
                    .filter(t => t.type === 'expense')
                    .reduce((sum, t) => sum + Number(t.amount), 0);

                const dailyBalance = dailyIncome - dailyExpense;

                return (
                    <div key={dateStr} className="animate-fade-in-up">
                        {/* Enhanced Date Header with Verdict */}
                        <div className="sticky top-0 z-10 bg-[#F9F6F2]/95 dark:bg-[#0D1117]/95 backdrop-blur-sm shadow-sm py-2.5 mb-2 px-2 flex justify-between items-center border-b border-gray-200 dark:border-gray-800 transition-colors rounded-xl mx-[-4px]">
                            <h3 className="font-bold text-gray-600 dark:text-gray-300 text-xs uppercase tracking-widest pl-1">
                                {new Date(dateStr).toLocaleDateString(undefined, { weekday: 'short', day: 'numeric', month: 'short' })}
                            </h3>

                            <div className="flex items-center gap-3">
                                {/* Income Summary */}
                                {dailyIncome > 0 && (
                                    <div className="flex items-center text-[10px] font-bold text-emerald-600 dark:text-emerald-400">
                                        <ArrowDownLeft className="w-3 h-3 mr-0.5" />
                                        <span>{dailyIncome.toLocaleString('en-IN', { maximumFractionDigits: 0 })}</span>
                                    </div>
                                )}

                                {/* Expense Summary */}
                                {dailyExpense > 0 && (
                                    <div className="flex items-center text-[10px] font-bold text-rose-600 dark:text-rose-400">
                                        <ArrowUpRight className="w-3 h-3 mr-0.5" />
                                        <span>{dailyExpense.toLocaleString('en-IN', { maximumFractionDigits: 0 })}</span>
                                    </div>
                                )}

                                {/* Verdict Pill */}
                                <div className={`px-2 py-0.5 rounded-md text-[10px] font-bold tabular-nums border ${
                                    dailyBalance >= 0 
                                        ? 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-300 border-emerald-200 dark:border-emerald-800' 
                                        : 'bg-rose-100 dark:bg-rose-900/30 text-rose-700 dark:text-rose-300 border-rose-200 dark:border-rose-800'
                                }`}>
                                    {dailyBalance >= 0 ? '+' : ''}{dailyBalance.toLocaleString('en-IN', { maximumFractionDigits: 0 })}
                                </div>
                            </div>
                        </div>

                        <div className="flex flex-col gap-3">
                            {dayTransactions.map((t) => {
                                const isIncome = t.type === 'income';
                                const isExpense = t.type === 'expense';
                                const isSelected = selectedIds?.has(t.id);

                                // Fuel Specific Logic
                                let mileageInfo = null;
                                let vehicleName = null;
                                if (t.category === 'Fuel' && t.metadata) {
                                    const { vehicle_name, km_driven, fuel_quantity } = t.metadata;
                                    vehicleName = vehicle_name;
                                    if (fuel_quantity && km_driven) {
                                        mileageInfo = `${(km_driven / fuel_quantity).toFixed(1)} km/l`;
                                    } else if (km_driven) {
                                        mileageInfo = `₹${(t.amount / km_driven).toFixed(2)}/km`;
                                    }
                                }

                                return (
                                    <div
                                        key={t.id}
                                        onPointerDown={() => handlePointerDown(t.id)}
                                        onPointerUp={handlePointerUp}
                                        onPointerLeave={handlePointerUp}
                                        onPointerCancel={handlePointerUp}
                                        onClick={() => handleClick(t)}
                                        className={`group relative flex items-center justify-between p-4 rounded-2xl border transition-all duration-200 text-left active:scale-[0.99] cursor-pointer
                                            ${isSelected 
                                                ? 'bg-indigo-50 dark:bg-indigo-900/20 border-indigo-500 shadow-md scale-[0.99]' 
                                                : 'bg-white dark:bg-[#1e1f22] border-gray-100 dark:border-gray-800 hover:border-gray-300 dark:hover:border-gray-600 shadow-sm hover:shadow-lg'
                                            }
                                        `}
                                    >
                                        <div className="flex items-center gap-4 min-w-0 flex-1">
                                            {/* Icon or Checkbox */}
                                            <div className={`w-12 h-12 rounded-xl flex items-center justify-center flex-shrink-0 transition-transform ${isSelectionMode ? '' : 'group-hover:scale-105'} 
                                                ${isSelected ? 'bg-indigo-500 text-white' : 
                                                    isIncome ? 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400' :
                                                    isExpense ? 'bg-rose-100 dark:bg-rose-900/30 text-rose-600 dark:text-rose-400' :
                                                    'bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400'
                                                }`}>
                                                {isSelectionMode ? (
                                                    isSelected ? <Check className="w-6 h-6" /> : <div className="w-5 h-5 rounded-full border-2 border-gray-400 dark:border-gray-600" />
                                                ) : (
                                                    <CategoryIcon categoryId={t.category} type={t.type} className="w-5 h-5" />
                                                )}
                                            </div>

                                            <div className="min-w-0 flex flex-col gap-0.5 flex-1 pr-2">
                                                <p className={`font-bold truncate text-base leading-tight ${isSelected ? 'text-indigo-900 dark:text-indigo-100' : 'text-gray-900 dark:text-white'}`}>
                                                    {t.description}
                                                </p>
                                                <div className="flex items-center gap-2 text-xs font-medium text-gray-500 dark:text-gray-400 flex-wrap">
                                                    <span className="capitalize truncate">{t.category}</span>
                                                    <span className="w-1 h-1 bg-gray-300 dark:bg-gray-600 rounded-full flex-shrink-0"></span>
                                                    <span className="opacity-70 truncate">{t.payment_method}</span>

                                                    {/* Fuel Vehicle Info */}
                                                    {vehicleName && (
                                                        <>
                                                            <span className="w-1 h-1 bg-gray-300 dark:bg-gray-600 rounded-full flex-shrink-0"></span>
                                                            <span className="flex items-center gap-1 bg-gray-100 dark:bg-gray-800 px-1.5 py-0.5 rounded text-[10px] text-gray-600 dark:text-gray-300">
                                                                <Car className="w-3 h-3" /> {vehicleName}
                                                            </span>
                                                        </>
                                                    )}
                                                    {mileageInfo && (
                                                        <>
                                                            <span className="flex items-center gap-1 bg-emerald-50 dark:bg-emerald-900/20 px-1.5 py-0.5 rounded text-[10px] text-emerald-600 dark:text-emerald-400 font-bold">
                                                                <Fuel className="w-3 h-3" /> {mileageInfo}
                                                            </span>
                                                        </>
                                                    )}
                                                </div>
                                            </div>
                                        </div>

                                        <div className="flex flex-col items-end gap-0.5 pl-1 flex-shrink-0">
                                            <span className={`text-base font-bold tabular-nums whitespace-nowrap flex-shrink-0 ${
                                                isIncome ? 'text-emerald-600 dark:text-emerald-400' : 
                                                isExpense ? 'text-red-600 dark:text-red-400' : 
                                                't
